import { useState } from 'react';
import { Card, Stack, Row, Text } from '@ggui-ai/design/primitives';

interface ForecastDay {
  dayName: string;
  icon: string;
  high: number;
  low: number;
}

interface Props {
  // Current weather data
  currentTemp: number;
  condition: 'sunny' | 'cloudy' | 'rainy' | 'snowy' | 'stormy' | 'windy';
  conditionLabel?: string;
  humidity: number;
  windSpeed: number;
  windUnit?: 'mph' | 'km/h';
  tempUnit?: 'F' | 'C';

  // Forecast data
  forecast?: ForecastDay[];

  // Location (optional)
  location?: string;
}

// Weather emoji mapping
const weatherEmojis: Record<string, string> = {
  sunny: '☀️',
  cloudy: '☁️',
  rainy: '🌧️',
  snowy: '❄️',
  stormy: '⛈️',
  windy: '💨',
};

export default function WeatherCard({
  currentTemp,
  condition,
  conditionLabel,
  humidity,
  windSpeed,
  windUnit = 'mph',
  tempUnit = 'F',
  forecast = [],
  location = 'Current Location',
}: Props) {
  const weatherIcon = weatherEmojis[condition] || '🌤️';
  const displayCondition = conditionLabel || condition.charAt(0).toUpperCase() + condition.slice(1);

  return (
    <Card
      padding={24}
      shadow="md"
      border={true}
      style={{
        maxWidth: '100%',
        background: `linear-gradient(135deg, var(--ggui-color-primary-50, #f0f9ff), var(--ggui-color-neutral-50, #f9fafb))`,
        borderColor: 'var(--ggui-color-primary-200, #bae6fd)',
      }}
    >
      <Stack direction="vertical" gap={20}>
        {/* Header with location */}
        <Stack direction="vertical" gap={4}>
          <Text
            variant="label"
            color="var(--ggui-color-neutral-500, #6b7280)"
          >
            {location}
          </Text>
        </Stack>

        {/* Current Weather Section */}
        <Stack direction="horizontal" align="center" gap={24}>
          {/* Temperature and Icon */}
          <Stack direction="vertical" align="center" gap={8}>
            <div style={{
              fontSize: '64px',
              lineHeight: '1',
              margin: '0 var(--ggui-spacing-2, 8px) 0 0',
            }}>
              {weatherIcon}
            </div>
            <Text
              variant="h1"
              color="var(--ggui-color-primary-900, #0c4a6e)"
              weight="bold"
              align="center"
            >
              {currentTemp}°{tempUnit}
            </Text>
          </Stack>

          {/* Condition and Details */}
          <Stack direction="vertical" gap={12}>
            <Text
              variant="h3"
              color="var(--ggui-color-neutral-700, #374151)"
              weight="semibold"
            >
              {displayCondition}
            </Text>

            {/* Humidity and Wind Speed */}
            <Stack direction="vertical" gap={8}>
              <Row gap={16} align="center">
                <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--ggui-spacing-2, 8px)' }}>
                  <span style={{ fontSize: '18px' }}>💧</span>
                  <Text
                    variant="body"
                    color="var(--ggui-color-neutral-700, #374151)"
                  >
                    Humidity: <span style={{ fontWeight: 'var(--ggui-font-weight-semibold, 600)' }}>{humidity}%</span>
                  </Text>
                </div>
              </Row>
              <Row gap={16} align="center">
                <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--ggui-spacing-2, 8px)' }}>
                  <span style={{ fontSize: '18px' }}>💨</span>
                  <Text
                    variant="body"
                    color="var(--ggui-color-neutral-700, #374151)"
                  >
                    Wind: <span style={{ fontWeight: 'var(--ggui-font-weight-semibold, 600)' }}>{windSpeed} {windUnit}</span>
                  </Text>
                </div>
              </Row>
            </Stack>
          </Stack>
        </Stack>

        {/* Divider */}
        <div style={{
          height: '1px',
          background: 'var(--ggui-color-primary-200, #bae6fd)',
          margin: 'var(--ggui-spacing-2, 8px) 0',
        }} />

        {/* 5-Day Forecast Section */}
        {forecast && forecast.length > 0 && (
          <Stack direction="vertical" gap={12}>
            <Text
              variant="label"
              color="var(--ggui-color-neutral-600, #4b5563)"
              weight="semibold"
            >
              5-Day Forecast
            </Text>

            <Stack direction="horizontal" gap={8} wrap={true}>
              {forecast.slice(0, 5).map((day, index) => {
                const keyVal = day.dayName + '-' + String(index);
                return (
                  <div
                    key={keyVal}
                    style={{
                      flex: '1 1 calc(20% - 7px)',
                      minWidth: '100px',
                      padding: 'var(--ggui-spacing-3, 12px)',
                      backgroundColor: 'rgba(255, 255, 255, 0.6)',
                      border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
                      borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                      display: 'flex',
                      flexDirection: 'column',
                      alignItems: 'center',
                      gap: 'var(--ggui-spacing-2, 8px)',
                      transition: 'all 200ms ease-out',
                      cursor: 'pointer',
                    }}
                    onMouseEnter={(e) => {
                      e.currentTarget.style.backgroundColor = 'rgba(255, 255, 255, 0.9)';
                      e.currentTarget.style.boxShadow = 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))';
                    }}
                    onMouseLeave={(e) => {
                      e.currentTarget.style.backgroundColor = 'rgba(255, 255, 255, 0.6)';
                      e.currentTarget.style.boxShadow = 'none';
                    }}
                  >
                    <Text
                      variant="label"
                      color="var(--ggui-color-neutral-700, #374151)"
                      weight="medium"
                    >
                      {day.dayName}
                    </Text>
                    <div style={{ fontSize: '28px', lineHeight: '1' }}>
                      {day.icon}
                    </div>
                    <Stack direction="horizontal" gap={6} align="center" justify="center">
                      <Text
                        variant="caption"
                        color="var(--ggui-color-primary-700, #0369a1)"
                        weight="semibold"
                      >
                        {day.high}°
                      </Text>
                      <Text
                        variant="caption"
                        color="var(--ggui-color-neutral-500, #6b7280)"
                      >
                        {day.low}°
                      </Text>
                    </Stack>
                  </div>
                );
              })}
            </Stack>
          </Stack>
        )}
      </Stack>
    </Card>
  );
}

import { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  RadioGroup,
  Checkbox,
  TextArea,
  Button,
  Divider,
  Box,
} from '@ggui-ai/design/primitives';

interface SurveyAnswers {
  name: string;
  email: string;
  satisfactionRating: string;
  interestingFeatures: string[];
  comments: string;
}

interface Props {
  satisfactionLabels?: string[];
  features?: Array<{ value: string; label: string }>;
  onSubmit: (answers: SurveyAnswers) => void;
}

function ReviewSection({
  title,
  children,
}: {
  title: string;
  children: React.ReactNode;
}) {
  return (
    <Card
      padding="var(--ggui-spacing-4, 16px)"
      border={true}
      shadow="none"
      style={{
        backgroundColor: 'var(--ggui-color-neutral-50, #f9fafb)',
      }}
    >
      <Stack direction="vertical" gap={12}>
        <Text
          variant="label"
          weight="semibold"
          color="var(--ggui-color-neutral-900, #111827)"
        >
          {title}
        </Text>
        {children}
      </Stack>
    </Card>
  );
}

function ProgressBar({
  currentStep,
  totalSteps,
}: {
  currentStep: number;
  totalSteps: number;
}) {
  const progress = ((currentStep + 1) / totalSteps) * 100;
  return (
    <Box
      padding="var(--ggui-spacing-6, 24px)"
      style={{
        backgroundColor: 'var(--ggui-color-neutral-50, #f9fafb)',
        borderBottom: '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
      }}
    >
      <Stack direction="vertical" gap={12}>
        <Row justify="between" align="center">
          <Text
            variant="label"
            color="var(--ggui-color-neutral-700, #374151)"
          >
            Step {currentStep + 1} of {totalSteps}
          </Text>
          <Text
            variant="caption"
            color="var(--ggui-color-neutral-500, #6b7280)"
          >
            {Math.round(progress)}%
          </Text>
        </Row>
        <div
          style={{
            width: '100%',
            height: '8px',
            backgroundColor: 'var(--ggui-color-neutral-200, #e5e7eb)',
            borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
            overflow: 'hidden',
          }}
        >
          <div
            style={{
              height: '100%',
              width: progress + '%',
              backgroundColor: 'var(--ggui-color-primary-600, #0284c7)',
              borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
              transition: 'width 300ms cubic-bezier(0.4, 0, 0.2, 1)',
            }}
          />
        </div>
      </Stack>
    </Box>
  );
}

export default function GeneratedComponent({
  satisfactionLabels = [
    'Very Unsatisfied',
    'Unsatisfied',
    'Neutral',
    'Satisfied',
    'Very Satisfied',
  ],
  features = [
    { value: 'feature1', label: 'Feature One' },
    { value: 'feature2', label: 'Feature Two' },
    { value: 'feature3', label: 'Feature Three' },
    { value: 'feature4', label: 'Feature Four' },
  ],
  onSubmit,
}: Props) {
  const [currentStep, setCurrentStep] = useState(0);
  const [answers, setAnswers] = useState<SurveyAnswers>({
    name: '',
    email: '',
    satisfactionRating: '',
    interestingFeatures: [],
    comments: '',
  });
  const [errors, setErrors] = useState<Record<string, string>>({});

  const totalSteps = 5;

  const validateEmail = (email: string) =>
    /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const validateStep = (step: number): boolean => {
    const newErrors: Record<string, string> = {};
    if (step === 0) {
      if (!answers.name.trim()) newErrors.name = 'Name is required';
      if (!answers.email.trim()) newErrors.email = 'Email is required';
      else if (!validateEmail(answers.email))
        newErrors.email = 'Please enter a valid email address';
    } else if (step === 1 && !answers.satisfactionRating) {
      newErrors.satisfactionRating = 'Please select a satisfaction rating';
    } else if (step === 2 && answers.interestingFeatures.length === 0) {
      newErrors.interestingFeatures = 'Please select at least one feature';
    }
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleNext = () => {
    validateStep(currentStep) &&
      setCurrentStep((p) => Math.min(p + 1, totalSteps - 1));
  };

  const handleBack = () => {
    setCurrentStep((p) => Math.max(p - 1, 0));
    setErrors({});
  };

  const updateAnswer = <K extends keyof SurveyAnswers>(
    key: K,
    value: SurveyAnswers[K]
  ) => {
    setAnswers((p) => ({ ...p, [key]: value }));
    if (errors[key]) setErrors((p) => ({ ...p, [key]: '' }));
  };

  const toggleFeature = (value: string, checked: boolean) => {
    updateAnswer(
      'interestingFeatures',
      checked
        ? [...answers.interestingFeatures, value]
        : answers.interestingFeatures.filter((f) => f !== value)
    );
  };

  const isNextDisabled =
    (currentStep === 0 &&
      (!answers.name.trim() ||
        !answers.email.trim() ||
        !validateEmail(answers.email))) ||
    (currentStep === 1 && !answers.satisfactionRating) ||
    (currentStep === 2 && answers.interestingFeatures.length === 0);

  const renderStep = () => {
    if (currentStep === 0)
      return (
        <Stack direction="vertical" gap={20}>
          <Stack direction="vertical" gap={4}>
            <Text
              variant="h2"
              color="var(--ggui-color-neutral-900, #111827)"
            >
              Personal Information
            </Text>
            <Text
              variant="body"
              color="var(--ggui-color-neutral-500, #6b7280)"
            >
              Please provide your name and email address
            </Text>
          </Stack>
          <Input
            label="Name"
            placeholder="Enter your full name"
            value={answers.name}
            onChange={(v) => updateAnswer('name', v)}
            error={errors.name}
            required
          />
          <Input
            label="Email Address"
            type="email"
            placeholder="you@example.com"
            value={answers.email}
            onChange={(v) => updateAnswer('email', v)}
            error={errors.email}
            required
          />
        </Stack>
      );

    if (currentStep === 1)
      return (
        <Stack direction="vertical" gap={20}>
          <Stack direction="vertical" gap={4}>
            <Text
              variant="h2"
              color="var(--ggui-color-neutral-900, #111827)"
            >
              Satisfaction Rating
            </Text>
            <Text
              variant="body"
              color="var(--ggui-color-neutral-500, #6b7280)"
            >
              How satisfied are you with our service?
            </Text>
          </Stack>
          <RadioGroup
            value={answers.satisfactionRating}
            onChange={(v) => updateAnswer('satisfactionRating', v)}
            options={[1, 2, 3, 4, 5].map((i) => ({
              value: i.toString(),
              label: i + ' - ' + satisfactionLabels[i - 1],
            }))}
            direction="vertical"
            error={errors.satisfactionRating}
          />
        </Stack>
      );

    if (currentStep === 2)
      return (
        <Stack direction="vertical" gap={20}>
          <Stack direction="vertical" gap={4}>
            <Text
              variant="h2"
              color="var(--ggui-color-neutral-900, #111827)"
            >
              Interesting Features
            </Text>
            <Text
              variant="body"
              color="var(--ggui-color-neutral-500, #6b7280)"
            >
              Which features interest you the most?
            </Text>
          </Stack>
          <Stack direction="vertical" gap={12}>
            {features.map((f) => (
              <Checkbox
                key={f.value}
                label={f.label}
                checked={answers.interestingFeatures.includes(f.value)}
                onChange={(c) => toggleFeature(f.value, c)}
              />
            ))}
          </Stack>
          {errors.interestingFeatures && (
            <Text
              variant="caption"
              color="var(--ggui-color-error-600, #dc2626)"
            >
              {errors.interestingFeatures}
            </Text>
          )}
        </Stack>
      );

    if (currentStep === 3)
      return (
        <Stack direction="vertical" gap={20}>
          <Stack direction="vertical" gap={4}>
            <Text
              variant="h2"
              color="var(--ggui-color-neutral-900, #111827)"
            >
              Additional Comments
            </Text>
            <Text
              variant="body"
              color="var(--ggui-color-neutral-500, #6b7280)"
            >
              Share any additional feedback (optional)
            </Text>
          </Stack>
          <Stack direction="vertical" gap={8}>
            <TextArea
              placeholder="Enter your comments here..."
              value={answers.comments}
              onChange={(v) =>
                v.length <= 500 && updateAnswer('comments', v)
              }
              rows={5}
              maxLength={500}
            />
            <Row justify="end">
              <Text
                variant="caption"
                color="var(--ggui-color-neutral-500, #6b7280)"
              >
                {answers.comments.length}/500 characters
              </Text>
            </Row>
          </Stack>
        </Stack>
      );

    const ratingIdx = parseInt(answers.satisfactionRating) - 1;
    const ratingLabel =
      answers.satisfactionRating +
      ' - ' +
      satisfactionLabels[Math.max(0, ratingIdx)];

    return (
      <Stack direction="vertical" gap={20}>
        <Stack direction="vertical" gap={4}>
          <Text variant="h2" color="var(--ggui-color-neutral-900, #111827)">
            Review Your Answers
          </Text>
          <Text
            variant="body"
            color="var(--ggui-color-neutral-500, #6b7280)"
          >
            Please review your information before submitting
          </Text>
        </Stack>
        <Stack direction="vertical" gap={16}>
          <ReviewSection title="Personal Information">
            <Row justify="between" align="start">
              <Stack direction="vertical" gap={4} align="start">
                <Text
                  variant="caption"
                  color="var(--ggui-color-neutral-500, #6b7280)"
                >
                  Name
                </Text>
                <Text
                  variant="body"
                  color="var(--ggui-color-neutral-900, #111827)"
                >
                  {answers.name}
                </Text>
              </Stack>
              <Stack direction="vertical" gap={4} align="start">
                <Text
                  variant="caption"
                  color="var(--ggui-color-neutral-500, #6b7280)"
                >
                  Email
                </Text>
                <Text
                  variant="body"
                  color="var(--ggui-color-neutral-900, #111827)"
                >
                  {answers.email}
                </Text>
              </Stack>
            </Row>
          </ReviewSection>
          <ReviewSection title="Satisfaction Rating">
            <Text
              variant="body"
              color="var(--ggui-color-neutral-900, #111827)"
            >
              {ratingLabel}
            </Text>
          </ReviewSection>
          <ReviewSection title="Interesting Features">
            <Stack direction="vertical" gap={8}>
              {answers.interestingFeatures.length > 0 ? (
                answers.interestingFeatures.map((fVal) => {
                  const f = features.find((x) => x.value === fVal);
                  return (
                    <Row
                      key={fVal}
                      align="center"
                      gap={8}
                      style={{
                        padding: 'var(--ggui-spacing-2, 8px)',
                        backgroundColor:
                          'var(--ggui-color-primary-50, #f0f9ff)',
                        borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                        borderLeft:
                          '3px solid var(--ggui-color-primary-600, #0284c7)',
                      }}
                    >
                      <Text
                        variant="body"
                        color="var(--ggui-color-neutral-900, #111827)"
                      >
                        {f?.label}
                      </Text>
                    </Row>
                  );
                })
              ) : (
                <Text
                  variant="body"
                  color="var(--ggui-color-neutral-500, #6b7280)"
                >
                  None selected
                </Text>
              )}
            </Stack>
          </ReviewSection>
          {answers.comments && (
            <ReviewSection title="Additional Comments">
              <Text
                variant="body"
                color="var(--ggui-color-neutral-900, #111827)"
                style={{ whiteSpace: 'pre-wrap' }}
              >
                {answers.comments}
              </Text>
            </ReviewSection>
          )}
        </Stack>
      </Stack>
    );
  };

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6, 24px)">
      <Card shadow="md" border={true} padding="0">
        <ProgressBar currentStep={currentStep} totalSteps={totalSteps} />
        <Box padding="var(--ggui-spacing-6, 24px)">{renderStep()}</Box>
        <Divider margin={0} />
        <Box
          padding="var(--ggui-spacing-6, 24px)"
          style={{
            backgroundColor: 'var(--ggui-color-neutral-50, #f9fafb)',
          }}
        >
          <Row justify="between" gap={12}>
            {currentStep > 0 ? (
              <Button variant="outline" onClick={handleBack}>
                Back
              </Button>
            ) : (
              <div />
            )}
            {currentStep < totalSteps - 1 ? (
              <Button
                variant="primary"
                onClick={handleNext}
                disabled={isNextDisabled}
              >
                Next
              </Button>
            ) : (
              <Button variant="primary" onClick={() => onSubmit(answers)}>
                Submit Survey
              </Button>
            )}
          </Row>
        </Box>
      </Card>
    </Container>
  );
}

import React, { useState } from 'react';
import {
  Container, Card, Stack, Row, Text, Input, Button, Select, Badge, Icon, Divider
} from '@ggui-ai/design/primitives';

// Priority color mapping using design tokens
const getPriorityColor = (priority: 'low' | 'medium' | 'high'): 'default' | 'primary' | 'secondary' | 'success' | 'warning' | 'error' | 'info' => {
  switch (priority) {
    case 'low': return 'success';
    case 'medium': return 'warning';
    case 'high': return 'error';
    default: return 'default';
  }
};

interface Task {
  id: string;
  title: string;
  priority: 'low' | 'medium' | 'high';
  assignee?: string;
  dueDate?: string;
  column: 'todo' | 'inprogress' | 'done';
}

interface Props {
  initialTasks?: Task[];
  onTaskUpdate?: (tasks: Task[]) => void;
}

let taskIdCounter = 0;

const generateTaskId = (): string => {
  taskIdCounter += 1;
  return 'task-' + taskIdCounter;
};

export default function KanbanBoard({ initialTasks = [], onTaskUpdate }: Props) {
  const [tasks, setTasks] = useState<Task[]>(initialTasks);
  const [addingTo, setAddingTo] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');

  const columns = [
    { id: 'todo', name: 'To Do' },
    { id: 'inprogress', name: 'In Progress' },
    { id: 'done', name: 'Done' },
  ];

  // Count tasks per column
  const getColumnCount = (columnId: string) => tasks.filter(t => t.column === columnId).length;
  const totalTasks = tasks.length;
  const completedTasks = tasks.filter(t => t.column === 'done').length;

  // Handle add task
  const handleAddTask = (columnId: string) => {
    if (!newTaskTitle.trim()) return;

    const newTask: Task = {
      id: generateTaskId(),
      title: newTaskTitle,
      priority: newTaskPriority,
      column: columnId as 'todo' | 'inprogress' | 'done',
    };

    const updatedTasks = [...tasks, newTask];
    setTasks(updatedTasks);
    onTaskUpdate?.(updatedTasks);

    setNewTaskTitle('');
    setNewTaskPriority('medium');
    setAddingTo(null);
  };

  // Handle move task
  const handleMoveTask = (taskId: string, newColumn: string) => {
    const updatedTasks = tasks.map(t =>
      t.id === taskId ? { ...t, column: newColumn as 'todo' | 'inprogress' | 'done' } : t
    );
    setTasks(updatedTasks);
    onTaskUpdate?.(updatedTasks);
  };

  // Handle edit task
  const handleEditTask = (taskId: string, newTitle: string) => {
    if (!newTitle.trim()) return;

    const updatedTasks = tasks.map(t =>
      t.id === taskId ? { ...t, title: newTitle } : t
    );
    setTasks(updatedTasks);
    onTaskUpdate?.(updatedTasks);

    setEditingTaskId(null);
    setEditingTitle('');
  };

  // Handle delete task
  const handleDeleteTask = (taskId: string) => {
    const updatedTasks = tasks.filter(t => t.id !== taskId);
    setTasks(updatedTasks);
    onTaskUpdate?.(updatedTasks);
  };

  // Get initials from assignee name
  const getInitials = (name: string) => {
    return name
      .split(' ')
      .map(part => part[0])
      .join('')
      .toUpperCase()
      .slice(0, 2);
  };

  // Render task card
  const renderTaskCard = (task: Task) => {
    const isEditing = editingTaskId === task.id;

    return (
      <Card
        key={task.id}
        padding={12}
        shadow="sm"
        border={true}
        style={{
          backgroundColor: 'var(--ggui-color-neutral-50)',
          cursor: 'pointer',
          transition: 'box-shadow 0.2s',
          marginBottom: 'var(--ggui-spacing-2)',
        }}
        onMouseEnter={(e) => {
          (e.currentTarget as HTMLDivElement).style.boxShadow = 'var(--ggui-shape-shadow-md)';
        }}
        onMouseLeave={(e) => {
          (e.currentTarget as HTMLDivElement).style.boxShadow = 'var(--ggui-shape-shadow-sm)';
        }}
      >
        <Stack direction="vertical" gap={8}>
          {/* Task title / edit mode */}
          {isEditing ? (
            <Row gap={6} align="stretch">
              <Input
                label="Task title"
                value={editingTitle}
                onChange={setEditingTitle}
                placeholder="Enter task title"
              />
              <Button
                variant="primary"
                size="xs"
                onClick={() => handleEditTask(task.id, editingTitle)}
              >
                Save
              </Button>
              <Button
                variant="ghost"
                size="xs"
                onClick={() => setEditingTaskId(null)}
              >
                Cancel
              </Button>
            </Row>
          ) : (
            <div
              style={{
                display: 'flex',
                justifyContent: 'space-between',
                alignItems: 'flex-start',
                gap: 'var(--ggui-spacing-2)',
              }}
            >
              <Text
                variant="body"
                weight="medium"
                style={{
                  flex: 1,
                  wordWrap: 'break-word',
                  cursor: 'pointer',
                  padding: 'var(--ggui-spacing-1)',
                  borderRadius: 'var(--ggui-shape-radius-sm)',
                }}
                onDoubleClick={() => {
                  setEditingTaskId(task.id);
                  setEditingTitle(task.title);
                }}
              >
                {task.title}
              </Text>
              <Button
                variant="ghost"
                size="xs"
                onClick={() => {
                  setEditingTaskId(task.id);
                  setEditingTitle(task.title);
                }}
                title="Edit task"
              >
                <Icon name="settings" size={14} />
              </Button>
            </div>
          )}

          {/* Priority badge */}
          <Badge variant={getPriorityColor(task.priority)} size="sm" pill>
            {task.priority.charAt(0).toUpperCase() + task.priority.slice(1)}
          </Badge>

          {/* Assignee and due date */}
          <Row gap={8} align="center">
            {task.assignee && (
              <div
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  width: 24,
                  height: 24,
                  borderRadius: '50%',
                  backgroundColor: 'var(--ggui-color-primary-200)',
                  color: 'var(--ggui-color-primary-900)',
                  fontSize: 'var(--ggui-font-size-xs)',
                  fontWeight: 'var(--ggui-font-weight-semibold)',
                  title: task.assignee,
                }}
              >
                {getInitials(task.assignee)}
              </div>
            )}
            {task.dueDate && (
              <Text variant="caption" color="var(--ggui-color-neutral-500)">
                {formatDate(task.dueDate)}
              </Text>
            )}
          </Row>

          {/* Move and delete controls */}
          <Row gap={6} justify="between">
            <Select
              label="Move to"
              value=""
              onChange={(col) => {
                if (col) handleMoveTask(task.id, col);
              }}
              options={columns
                .filter(c => c.id !== task.column)
                .map(c => ({ value: c.id, label: 'Move to ' + c.name }))}
              placeholder="Move..."
              style={{ flex: 1 }}
            />
            <Button
              variant="ghost"
              size="xs"
              onClick={() => handleDeleteTask(task.id)}
              title="Delete task"
            >
              <Icon name="x" size={14} />
            </Button>
          </Row>
        </Stack>
      </Card>
    );
  };

  // Render column
  const renderColumn = (column: { id: string; name: string }) => {
    const columnTasks = tasks.filter(t => t.column === column.id);
    const isAddingToThis = addingTo === column.id;

    return (
      <Card key={column.id} padding={16} shadow="sm" border={true}>
        <Stack direction="vertical" gap={12} style={{ minHeight: 500 }}>
          {/* Column header */}
          <Row justify="between" align="center">
            <Text variant="h3" weight="semibold">
              {column.name}
            </Text>
            <Badge variant="secondary" size="sm">
              {getColumnCount(column.id)}
            </Badge>
          </Row>

          <Divider margin={8} />

          {/* Task list */}
          <Stack direction="vertical" gap={0} style={{ flex: 1 }}>
            {columnTasks.map(task => renderTaskCard(task))}
            {columnTasks.length === 0 && (
              <div
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  flex: 1,
                  minHeight: 200,
                }}
              >
                <Text variant="caption" color="var(--ggui-color-neutral-500)">
                  No tasks
                </Text>
              </div>
            )}
          </Stack>

          {/* Add task section */}
          {isAddingToThis ? (
            <Card
              padding={12}
              shadow="none"
              border={true}
              style={{
                borderStyle: 'dashed',
                backgroundColor: 'var(--ggui-color-primary-50)',
              }}
            >
              <Stack direction="vertical" gap={8}>
                <Input
                  label="Task title"
                  placeholder="Enter task title"
                  value={newTaskTitle}
                  onChange={setNewTaskTitle}
                />
                <Select
                  label="Priority"
                  value={newTaskPriority}
                  onChange={(v) => setNewTaskPriority(v as 'low' | 'medium' | 'high')}
                  options={[
                    { value: 'low', label: 'Low Priority' },
                    { value: 'medium', label: 'Medium Priority' },
                    { value: 'high', label: 'High Priority' },
                  ]}
                />
                <Row gap={8}>
                  <Button
                    variant="primary"
                    size="sm"
                    fullWidth
                    onClick={() => handleAddTask(column.id)}
                  >
                    Add Task
                  </Button>
                  <Button
                    variant="outline"
                    size="sm"
                    fullWidth
                    onClick={() => setAddingTo(null)}
                  >
                    Cancel
                  </Button>
                </Row>
              </Stack>
            </Card>
          ) : (
            <Button
              variant="outline"
              fullWidth
              size="sm"
              leftIcon={<Icon name="plus" size={16} />}
              onClick={() => setAddingTo(column.id)}
            >
              Add Task
            </Button>
          )}
        </Stack>
      </Card>
    );
  };

  return (
    <Container maxWidth="full" padding={24}>
      <Stack direction="vertical" gap={24}>
        {/* Header with summary */}
        <Stack direction="vertical" gap={12}>
          <Text variant="h1" weight="bold">
            Task Board
          </Text>

          {/* Summary bar */}
          <Row gap={16} align="center">
            <Card padding={12} shadow="sm" border={true}>
              <Row gap={12} align="center">
                <div>
                  <Text variant="label" color="var(--ggui-color-neutral-500)">
                    Total Tasks
                  </Text>
                  <Text variant="h2" weight="bold" color="var(--ggui-color-primary-600)">
                    {totalTasks}
                  </Text>
                </div>
              </Row>
            </Card>

            <Card padding={12} shadow="sm" border={true}>
              <Row gap={12} align="center">
                <div>
                  <Text variant="label" color="var(--ggui-color-neutral-500)">
                    Completed
                  </Text>
                  <Text variant="h2" weight="bold" color="var(--ggui-color-success-600)">
                    {completedTasks}
                  </Text>
                </div>
              </Row>
            </Card>

            {totalTasks > 0 && (
              <Card padding={12} shadow="sm" border={true}>
                <Row gap={12} align="center">
                  <div>
                    <Text variant="label" color="var(--ggui-color-neutral-500)">
                      Progress
                    </Text>
                    <Text variant="h2" weight="bold" color="var(--ggui-color-primary-600)">
                      {Math.round((completedTasks / totalTasks) * 100)}%
                    </Text>
                  </div>
                </Row>
              </Card>
            )}
          </Row>
        </Stack>

        <Divider margin={0} />

        {/* Kanban board columns */}
        <Row gap={16} align="start" style={{ overflowX: 'auto' }}>
          {columns.map(column => (
            <div key={column.id} style={{ minWidth: 350, flex: '0 0 350px' }}>
              {renderColumn(column)}
            </div>
          ))}
        </Row>
      </Stack>
    </Container>
  );
}

// Helper to format date
function formatDate(dateStr: string): string {
  const date = new Date(dateStr);
  const options: Intl.DateTimeFormatOptions = {
    month: 'short',
    day: 'numeric',
  };
  return date.toLocaleDateString('en-US', options);
}

