interface ElementCellProps {
  element: Element;
  isSelected: boolean;
  onClick: () => void;
  motionEnabled: boolean;
}

function ElementCell({ element, isSelected, onClick, motionEnabled }: ElementCellProps) {
  const colors = CATEGORY_COLORS[element.category] || {
    bg: 'var(--ggui-color-neutral-100, #f3f4f6)',
    textColor: 'var(--ggui-color-neutral-900, #111827)',
    borderColor: '#111827',
    badge: 'secondary',
  };

  const borderString = isSelected
    ? '3px solid ' + colors.borderColor
    : '1px solid var(--ggui-color-neutral-300, #d1d5db)';

  return (
    <Box
      style={{
        backgroundColor: colors.bg,
        border: borderString,
        borderRadius: 'var(--ggui-shape-radius-md, 8px)',
        padding: 'var(--ggui-spacing-2, 8px)',
        cursor: 'pointer',
        aspectRatio: '1',
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        transition: 'all 200ms ease-out',
        transform: isSelected ? 'scale(1.05)' : 'scale(1)',
        opacity: 1,
        position: 'relative',
      }}
      onClick={onClick}
    >
      <Text
        variant="caption"
        style={{
          color: colors.textColor,
          fontSize: 'var(--ggui-font-size-xs, 12px)',
          position: 'absolute',
          top: '4px',
          left: '4px',
        }}
      >
        {element.atomicNumber}
      </Text>
      <Text
        style={{
          color: colors.textColor,
          fontSize: 'var(--ggui-font-size-2xl, 24px)',
          fontWeight: 'var(--ggui-font-weight-bold, 700)',
          lineHeight: '1',
        }}
      >
        {element.symbol}
      </Text>
    </Box>
  );
}

export default function GeneratedComponent({ elements = DEFAULT_ELEMENTS }: Props) {
  const { motionEnabled } = useMotion();
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<Element | null>(null);

  // Filter elements
  const filteredElements = useMemo(() => {
    return elements.filter(el =>
      el.symbol.toLowerCase().includes(searchQuery.toLowerCase()) ||
      el.name.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [elements, searchQuery]);

  // Generate grid cells - 7 periods × 18 groups
  const renderGrid = () => {
    const cells = [];
    const allElements: Record<string, Element> = {};
    elements.forEach(el => {
      allElements[el.period + '-' + el.group] = el;
    });

    for (let period = 1; period <= 7; period++) {
      for (let group = 1; group <= 18; group++) {
        const key = period + '-' + group;
        const element = allElements[key];

        cells.push(
          <Box key={key} style={{ aspectRatio: '1' }}>
            {element && filteredElements.includes(element) ? (
              <ElementCell
                element={element}
                isSelected={selectedElement?.atomicNumber === element.atomicNumber}
                onClick={() => setSelectedElement(element)}
                motionEnabled={motionEnabled}
              />
            ) : null}
          </Box>
        );
      }
    }

    return cells;
  };

  // Get unique categories and their colors
  const categories = useMemo(() => {
    const cats = new Set(elements.map(el => el.category));
    return Array.from(cats).sort();
  }, [elements]);

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="full" padding={24} center={false}>
        <Stack direction="vertical" gap={24}>
          {/* Header */}
          <Stack direction="vertical" gap={8}>
            <Text variant="h1" style={{ color: 'var(--ggui-color-primary-900, #0c4a6e)' }}>
              Interactive Periodic Table of Elements
            </Text>
            <Text style={{ color: 'var(--ggui-color-neutral-600, #4b5563)' }}>
              Click elements to view details. Use the search to filter by name or symbol.
            </Text>
          </Stack>

          {/* Search */}
          <Input
            label="Search elements"
            placeholder="Search by element name or symbol (e.g., 'Hydrogen', 'H')..."
            value={searchQuery}
            onChange={setSearchQuery}
          />

          {/* Legend */}
          <Card padding={16}>
            <Stack direction="vertical" gap={12}>
              <Text variant="label" style={{ color: 'var(--ggui-color-neutral-700, #374151)' }}>
                Category Legend:
              </Text>
              <Row gap={12} wrap>
                {categories.map(category => {
                  const colors = CATEGORY_COLORS[category];
                  return (
                    <Row key={category} gap={8} align="center">
                      <Box
                        style={{
                          width: '16px',
                          height: '16px',
                          borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                          backgroundColor: colors?.bg || 'var(--ggui-color-neutral-200, #e5e7eb)',
                          border: '1px solid var(--ggui-color-neutral-300, #d1d5db)',
                        }}
                      />
                      <Text
                        style={{
                          color: 'var(--ggui-color-neutral-700, #374151)',
                          fontSize: 'var(--ggui-font-size-sm, 14px)',
                        }}
                      >
                        {category}
                      </Text>
                    </Row>
                  );
                })}
              </Row>
            </Stack>
          </Card>

          {/* Main Content */}
          <Row gap={24} align="start">
            {/* Grid */}
            <Box
              style={{
                flex: 1,
                display: 'grid',
                gridTemplateColumns: 'repeat(18, minmax(50px, 1fr))',
                gap: 'var(--ggui-spacing-2, 8px)',
                autoRows: 'minmax(50px, 1fr)',
              }}
            >
              {renderGrid()}
            </Box>

            {/* Detail Panel */}
            {selectedElement && (
              <Box style={{ minWidth: '320px' }}>
                <DetailPanel
                  element={selectedElement}
                  onClose={() => setSelectedElement(null)}
                />
              </Box>
            )}
          </Row>

          {/* Results Info */}
          {searchQuery && (
            <Card
              padding={16}
              style={{
                backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
              }}
            >
              <Text style={{ color: 'var(--ggui-color-primary-900, #0c4a6e)' }}>
                Showing {filteredElements.length} of {elements.length} elements
              </Text>
            </Card>
          )}
        </Stack>
      </Container>
    </>
  );
}

import { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Button,
  Tabs,
  Badge,
  Icon,
  Divider,
  Box,
  Table,
} from '@ggui-ai/design/primitives';

interface Review {
  id: string;
  author: string;
  rating: number;
  text: string;
  date: string;
}

interface Specification {
  key: string;
  value: string;
}

interface Props {
  productId: string;
  productName: string;
  price: number;
  currency: string;
  rating: number;
  stockQuantity: number;
  inStock: boolean;
  description: string;
  specifications: Specification[];
  reviews: Review[];
  onAddToCart: (data: { productId: string; quantity: number }) => void;
}

function StarRating({ rating, maxRating = 5 }: { rating: number; maxRating?: number }) {
  return (
    <Row gap={4} align="center">
      {Array.from({ length: maxRating }).map((_, i) => (
        <Icon
          key={i}
          name={i < Math.floor(rating) ? 'check' : 'x'}
          size={16}
          color={
            i < Math.floor(rating)
              ? 'var(--ggui-color-warning-500, #f59e0b)'
              : 'var(--ggui-color-neutral-300, #d1d5db)'
          }
          style={{ transform: 'scaleX(-1)', opacity: i < Math.floor(rating) ? 1 : 0.5 }}
        />
      ))}
      <Text variant="body" color="var(--ggui-color-neutral-600, #4b5563)">
        {rating.toFixed(1)} ({rating > 0 ? Math.round(rating * 10) : 0}%)
      </Text>
    </Row>
  );
}

export default function ProductDetailPage({
  productId,
  productName,
  price,
  currency,
  rating,
  stockQuantity,
  inStock,
  description,
  specifications,
  reviews,
  onAddToCart,
}: Props) {
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  const handleIncrement = () => {
    if (quantity < stockQuantity) {
      setQuantity(q => q + 1);
    }
  };

  const handleDecrement = () => {
    if (quantity > 1) {
      setQuantity(q => q - 1);
    }
  };

  const handleAddToCart = () => {
    onAddToCart({ productId, quantity });
  };

  const stockStatus = inStock
    ? stockQuantity <= 10
      ? 'Low Stock'
      : 'In Stock'
    : 'Out of Stock';

  const stockBadgeVariant = inStock
    ? stockQuantity <= 10
      ? 'warning'
      : 'success'
    : 'error';

  const currencySymbol =
    currency === 'USD'
      ? '$'
      : currency === 'EUR'
        ? '€'
        : currency === 'GBP'
          ? '£'
          : currency;

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack direction="vertical" gap={32}>
        {/* Top Section: Product Image & Details */}
        <Stack
          direction="horizontal"
          gap={32}
          align="start"
          wrap
          style={{
            '@media (max-width: 768px)': {
              direction: 'vertical',
            },
          }}
        >
          {/* Product Image Placeholder */}
          <Box
            style={{
              backgroundColor: 'var(--ggui-color-primary-100, #e0f2fe)',
              borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
              minWidth: '300px',
              width: '100%',
              maxWidth: '400px',
              aspectRatio: '1',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              flexShrink: 0,
            }}
          >
            <Text
              variant="h3"
              color="var(--ggui-color-primary-700, #0369a1)"
              align="center"
              style={{ padding: 'var(--ggui-spacing-6, 24px)' }}
            >
              {productName}
            </Text>
          </Box>

          {/* Product Details */}
          <Stack
            direction="vertical"
            gap={20}
            style={{ flex: 1, minWidth: '300px' }}
          >
            {/* Title */}
            <Text variant="h2">{productName}</Text>

            {/* Price */}
            <Text
              variant="h3"
              color="var(--ggui-color-primary-600, #0284c7)"
              weight="bold"
            >
              {currencySymbol}
              {price.toFixed(2)}
            </Text>

            {/* Rating */}
            <Stack direction="vertical" gap={8}>
              <Text variant="label" color="var(--ggui-color-neutral-700, #374151)">
                Rating
              </Text>
              <StarRating rating={rating} />
            </Stack>

            <Divider margin={16} />

            {/* Stock Status Badge */}
            <Badge variant={stockBadgeVariant}>{stockStatus}</Badge>

            {/* Quantity Selector */}
            <Stack direction="vertical" gap={8}>
              <Text variant="label" color="var(--ggui-color-neutral-700, #374151)">
                Quantity
              </Text>
              <Row gap={12} align="center">
                <Button
                  variant="outline"
                  size="sm"
                  onClick={handleDecrement}
                  disabled={quantity <= 1}
                >
                  <Icon name="minus" size={16} />
                </Button>
                <Text
                  variant="body"
                  style={{
                    minWidth: '40px',
                    textAlign: 'center',
                  }}
                >
                  {quantity}
                </Text>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={handleIncrement}
                  disabled={quantity >= stockQuantity || !inStock}
                >
                  <Icon name="plus" size={16} />
                </Button>
                <Text
                  variant="caption"
                  color="var(--ggui-color-neutral-500, #6b7280)"
                >
                  (Max: {stockQuantity})
                </Text>
              </Row>
            </Stack>

            {/* Add to Cart Button */}
            <Button
              variant="primary"
              size="lg"
              onClick={handleAddToCart}
              disabled={!inStock}
              fullWidth
            >
              {inStock ? 'Add to Cart' : 'Out of Stock'}
            </Button>
          </Stack>
        </Stack>

        <Divider margin={24} />

        {/* Middle Section: Tabs */}
        <Tabs
          activeKey={activeTab}
          onChange={setActiveTab}
          items={[
            {
              key: 'description',
              label: 'Description',
              content: (
                <Card padding={24}>
                  <Text variant="body">{description}</Text>
                </Card>
              ),
            },
            {
              key: 'specifications',
              label: 'Specifications',
              content: (
                <Card padding={24}>
                  {specifications && specifications.length > 0 ? (
                    <Table
                      columns={[
                        { key: 'key', header: 'Specification', width: '40%' },
                        { key: 'value', header: 'Value', width: '60%' },
                      ]}
                      data={specifications}
                      compact
                      bordered
                    />
                  ) : (
                    <Text
                      variant="body"
                      color="var(--ggui-color-neutral-500, #6b7280)"
                    >
                      No specifications available.
                    </Text>
                  )}
                </Card>
              ),
            },
            {
              key: 'reviews',
              label: 'Reviews',
              content: (
                <Card padding={24}>
                  {reviews && reviews.length > 0 ? (
                    <Stack direction="vertical" gap={20}>
                      {reviews.map(review => (
                        <Card
                          key={review.id}
                          padding={16}
                          shadow="sm"
                          border={true}
                          style={{
                            backgroundColor:
                              'var(--ggui-color-neutral-50, #f9fafb)',
                          }}
                        >
                          <Stack direction="vertical" gap={12}>
                            {/* Review Header */}
                            <Row justify="between" align="center">
                              <Text
                                variant="label"
                                weight="semibold"
                                color="var(--ggui-color-neutral-900, #111827)"
                              >
                                {review.author}
                              </Text>
                              <Text
                                variant="caption"
                                color="var(--ggui-color-neutral-500, #6b7280)"
                              >
                                {review.date}
                              </Text>
                            </Row>

                            {/* Review Rating */}
                            <Row gap={4}>
                              {Array.from({ length: 5 }).map((_, i) => (
                                <Icon
                                  key={i}
                                  name={
                                    i < review.rating ? 'check' : 'x'
                                  }
                                  size={16}
                                  color={
                                    i < review.rating
                                      ? 'var(--ggui-color-warning-500, #f59e0b)'
                                      : 'var(--ggui-color-neutral-300, #d1d5db)'
                                  }
                                  style={{
                                    transform: 'scaleX(-1)',
                                    opacity:
                                      i < review.rating
                                        ? 1
                                        : 0.5,
                                  }}
                                />
                              ))}
                            </Row>

                            {/* Review Text */}
                            <Text
                              variant="body"
                              color="var(--ggui-color-neutral-700, #374151)"
                            >
                              {review.text}
                            </Text>
                          </Stack>
                        </Card>
                      ))}
                    </Stack>
                  ) : (
                    <Text
                      variant="body"
                      color="var(--ggui-color-neutral-500, #6b7280)"
                    >
                      No reviews yet. Be the first to review!
                    </Text>
                  )}
                </Card>
              ),
            },
          ]}
        />
      </Stack>
    </Container>
  );
}

