import { useState, useEffect, useRef } from 'react';
import {
  Container, Card, Stack, Row, Text, Input, Button, Icon, Box,
  MotionKeyframes, useMotion
} from '@ggui-ai/design/primitives';

interface Message {
  id: string;
  sender: string;
  senderId: string;
  text: string;
  timestamp: string;
}

interface User {
  id: string;
  name: string;
}

interface Props {
  title?: string;
  participantCount?: number;
  initialMessages?: Message[];
  typingIndicators?: string[];
  user: User;
  onSend?: (data: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent({
  title = 'Chat',
  participantCount = 2,
  initialMessages = [],
  typingIndicators = [],
  user,
  onSend,
}: Props) {
  const [messages, setMessages] = useState<Message[]>(initialMessages);
  const [inputValue, setInputValue] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const { motionEnabled } = useMotion();

  // Handle new messages from props
  useEffect(() => {
    if (initialMessages.length > messages.length) {
      setMessages(initialMessages);
    }
  }, [initialMessages]);

  // Auto-scroll to bottom on new messages
  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, typingIndicators]);

  const handleSend = () => {
    if (!inputValue.trim()) return;

    const timestamp = new Date().toISOString();
    const messageId = String(Date.now()) + String(Math.random());

    // Add message to local state
    const newMessage: Message = {
      id: messageId,
      sender: user.name,
      senderId: user.id,
      text: inputValue,
      timestamp,
    };
    setMessages(prev => [...prev, newMessage]);

    // Notify parent
    onSend?.({ text: inputValue, timestamp });

    setInputValue('');
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const formatTime = (iso: string) => {
    try {
      const date = new Date(iso);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    } catch {
      return iso;
    }
  };

  const isCurrentUser = (senderId: string) => senderId === user.id;

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="lg" padding={0}>
        <Card padding={0} border={false} shadow="md" style={{ height: '100vh', display: 'flex', flexDirection: 'column' }}>
          {/* Header */}
          <Box
            padding="var(--ggui-spacing-4, 16px)"
            background="var(--ggui-color-primary-50, #f0f9ff)"
            borderRadius={0}
            style={{
              borderBottom: '1px solid var(--ggui-color-primary-200, #bae6fd)',
              flexShrink: 0,
            }}
          >
            <Row justify="between" align="center">
              <Stack direction="vertical" gap={4}>
                <Text variant="h3" weight="semibold" color="var(--ggui-color-primary-900, #0c4a6e)">
                  {title}
                </Text>
              </Stack>
              <Badge
                style={{
                  backgroundColor: 'var(--ggui-color-primary-100, #e0f2fe)',
                  color: 'var(--ggui-color-primary-700, #0369a1)',
                  padding: 'var(--ggui-spacing-1, 4px) var(--ggui-spacing-2, 8px)',
                  borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                  fontSize: 'var(--ggui-font-size-xs, 12px)',
                  fontWeight: 'var(--ggui-font-weight-medium, 500)',
                }}
              >
                {participantCount} participant{participantCount !== 1 ? 's' : ''}
              </Badge>
            </Row>
          </Box>

          {/* Messages Container */}
          <Box
            padding="var(--ggui-spacing-4, 16px)"
            background="var(--ggui-color-neutral-50, #f9fafb)"
            style={{
              flex: 1,
              overflowY: 'auto',
              display: 'flex',
              flexDirection: 'column',
              gap: 'var(--ggui-spacing-4, 16px)',
            }}
          >
            {messages.length === 0 && typingIndicators.length === 0 && (
              <Box
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  height: '100%',
                  minHeight: '200px',
                }}
              >
                <Text
                  color="var(--ggui-color-neutral-500, #6b7280)"
                  align="center"
                >
                  No messages yet. Start the conversation!
                </Text>
              </Box>
            )}

            {messages.map((msg, idx) => {
              const currentUser = isCurrentUser(msg.senderId);
              const delayMs = idx * 20;
              const delayStr = delayMs + 'ms';
              return (
                <Box
                  key={msg.id}
                  style={{
                    display: 'flex',
                    justifyContent: currentUser ? 'flex-end' : 'flex-start',
                    animation: motionEnabled ? 'ggui-slideInUp 200ms ease-out both' : 'none',
                    animationDelay: motionEnabled ? delayStr : '0ms',
                  }}
                >
                  <Box
                    padding="var(--ggui-spacing-3, 12px) var(--ggui-spacing-4, 16px)"
                    borderRadius="var(--ggui-shape-radius-lg, 12px)"
                    style={{
                      maxWidth: '60%',
                      backgroundColor: currentUser
                        ? 'var(--ggui-color-primary-600, #0284c7)'
                        : 'var(--ggui-color-neutral-200, #e5e7eb)',
                      wordBreak: 'break-word',
                    }}
                  >
                    {!currentUser && (
                      <Text
                        variant="caption"
                        weight="semibold"
                        color={currentUser ? '#ffffff' : 'var(--ggui-color-neutral-700, #374151)'}
                        style={{ display: 'block', marginBottom: 'var(--ggui-spacing-1, 4px)' }}
                      >
                        {msg.sender}
                      </Text>
                    )}
                    <Text
                      variant="body"
                      color={currentUser ? '#ffffff' : 'var(--ggui-color-neutral-900, #111827)'}
                      style={{ display: 'block', marginBottom: 'var(--ggui-spacing-1, 4px)' }}
                    >
                      {msg.text}
                    </Text>
                    <Text
                      variant="caption"
                      color={currentUser ? 'rgba(255,255,255,0.7)' : 'var(--ggui-color-neutral-500, #6b7280)'}
                    >
                      {formatTime(msg.timestamp)}
                    </Text>
                  </Box>
                </Box>
              );
            })}

            {/* Typing Indicator */}
            {typingIndicators.length > 0 && (
              <Box
                style={{
                  display: 'flex',
                  justifyContent: 'flex-start',
                  animation: motionEnabled ? 'ggui-slideInUp 200ms ease-out both' : 'none',
                }}
              >
                <Box
                  padding="var(--ggui-spacing-3, 12px) var(--ggui-spacing-4, 16px)"
                  borderRadius="var(--ggui-shape-radius-lg, 12px)"
                  style={{
                    backgroundColor: 'var(--ggui-color-neutral-200, #e5e7eb)',
                    display: 'flex',
                    gap: 'var(--ggui-spacing-1, 4px)',
                    alignItems: 'center',
                  }}
                >
                  <Text
                    variant="caption"
                    weight="semibold"
                    color="var(--ggui-color-neutral-700, #374151)"
                    style={{ marginRight: 'var(--ggui-spacing-1, 4px)' }}
                  >
                    {typingIndicators[0]} is typing
                  </Text>
                  <TypingDots motionEnabled={motionEnabled} />
                </Box>
              </Box>
            )}

            <div ref={messagesEndRef} />
          </Box>

          {/* Input Area */}
          <Box
            padding="var(--ggui-spacing-4, 16px)"
            background="var(--ggui-color-neutral-50, #f9fafb)"
            style={{
              borderTop: '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
              flexShrink: 0,
            }}
          >
            <Row gap={8} align="end">
              <Box style={{ flex: 1 }}>
                <Input
                  label="Message"
                  placeholder="Type a message..."
                  value={inputValue}
                  onChange={setInputValue}
                  onKeyDown={handleKeyDown}
                />
              </Box>
              <Button
                variant="primary"
                size="md"
                onClick={handleSend}
                disabled={!inputValue.trim()}
                rightIcon={<Icon name="chevron-right" size={16} />}
              >
                Send
              </Button>
            </Row>
          </Box>
        </Card>
      </Container>
    </>
  );
}

function Badge({ children, ...props }: any) {
  return <span {...props}>{children}</span>;
}

function TypingDots({ motionEnabled }: { motionEnabled: boolean }) {
  return (
    <span style={{ display: 'flex', gap: 'var(--ggui-spacing-1, 4px)', alignItems: 'center' }}>
      {[0, 1, 2].map(i => {
        const delayValue = i * 0.2;
        const delayStr = delayValue + 's';
        return (
          <span
            key={i}
            style={{
              width: '6px',
              height: '6px',
              borderRadius: '50%',
              backgroundColor: 'var(--ggui-color-neutral-500, #6b7280)',
              animation: motionEnabled
                ? `pulse 1.4s infinite`
                : 'none',
              animationDelay: motionEnabled ? delayStr : '0s',
            }}
          />
        );
      })}
      <style>{`
        @keyframes pulse {
          0%, 100% { opacity: 0.6; }
          50% { opacity: 1; }
        }
      `}</style>
    </span>
  );
}

