  onAddToCart?: (payload: { productId: string; quantity: number }) => void;
}

// ─── Star Rating ──────────────────────────────────────────────────────────────

function StarRating({ rating, size = 18 }: { rating: number; size?: number }) {
  return (
    <Row gap={2} align="center">
      {[1, 2, 3, 4, 5].map((star) => {
        const filled = star <= Math.round(rating);
        const partial = !filled && star - 1 < rating && rating < star;
        return (
          <span
            key={star}
            style={{
              fontSize: size,
              color: filled || partial
                ? 'var(--ggui-color-warning-500, #f59e0b)'
                : 'var(--ggui-color-neutral-300, #d1d5db)',
              lineHeight: 1,
              userSelect: 'none',
            }}
          >
            {filled || partial ? '★' : '☆'}
          </span>
        );
      })}
    </Row>
  );
}

// ─── Review Card ──────────────────────────────────────────────────────────────

function ReviewCard({ review }: { review: Review }) {
  return (
    <Card shadow="none" border={true} padding={16}>
      <Stack direction="vertical" gap={8}>
        <Row align="center" gap={8}>
          <div style={{
            width: 36,
            height: 36,
            borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
            background: 'var(--ggui-color-primary-100, #e0f2fe)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            flexShrink: 0,
          }}>
            <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)" weight="semibold">
              {review.author.charAt(0).toUpperCase()}
            </Text>
          </div>
          <Stack direction="vertical" gap={2}>
            <Text variant="label" weight="semibold">{review.author}</Text>
            <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">{review.date}</Text>
          </Stack>
          <Spacer />
          <StarRating rating={review.rating} size={14} />
        </Row>
        <Text variant="body" color="var(--ggui-color-neutral-700, #374151)">{review.text}</Text>
      </Stack>
    </Card>
  );
}

