                    ) : isLowStock ? (
                      <Badge variant="warning" size="md" pill>
                        {'Low Stock — Only ' + stockCount + ' left'}
                      </Badge>
                    ) : (
                      <Badge variant="success" size="md" pill>
                        {'In Stock — ' + stockCount + ' available'}
                      </Badge>
                    )}
                  </div>

                  <Divider margin={4} />

                  {/* Quantity Selector */}
                  <Stack direction="vertical" gap={10}>
                    <Text variant="label" weight="semibold" color="var(--ggui-color-neutral-700, #374151)">
                      Quantity
                    </Text>
                    <Row align="center" gap={8}>
                      <Button
                        variant="outline"
                        size="sm"
                        disabled={isOutOfStock || quantity <= 1}
                        onClick={handleDecrement}
                        leftIcon={<Icon name="minus" size={14} />}
                      >
                        {''}
                      </Button>

                      <div style={{
                        minWidth: 52,
                        textAlign: 'center',
                        padding: 'var(--ggui-spacing-1, 4px) var(--ggui-spacing-2, 8px)',
                        border: '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
                        borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                        background: 'var(--ggui-color-neutral-50, #f9fafb)',
                      }}>
                        <Text variant="label" weight="semibold" align="center">
                          {isOutOfStock ? '—' : String(quantity)}
                        </Text>
                      </div>

                      <Button
                        variant="outline"
                        size="sm"
                        disabled={isOutOfStock || quantity >= stockCount}
                        onClick={handleIncrement}
                        leftIcon={<Icon name="plus" size={14} />}
                      >
                        {''}
                      </Button>
                    </Row>
                  </Stack>

                  {/* Add to Cart */}
                  <Button
                    variant="primary"
                    size="lg"
                    fullWidth
                    disabled={isOutOfStock}
                    onClick={handleAddToCart}
                  >
                    {isOutOfStock ? 'Out of Stock' : 'Add ' + quantity + ' to Cart'}
                  </Button>

                </Stack>
              </div>
            </div>
          </Card>

          {/* ── MIDDLE SECTION — Tabs ──────────────────────────────────── */}
          <Card padding={24} shadow="sm">
            <Tabs
              activeKey={activeTab}
              onChange={setActiveTab}
              variant="line"
              size="md"
              items={[
                {
                  key: 'description',
                  label: 'Description',
                  content: descriptionContent,
                },
                {
                  key: 'specifications',
                  label: 'Specifications',
                  content: specsContent,
                },
                {
                  key: 'reviews',
                  label: reviewTabLabel,
                  content: reviewsContent,
                },
              ]}
            />
          </Card>

        </Stack>
      </Container>
    </>
  );
}

