import { useState, useEffect, useRef, useCallback } from 'react';
import {
  Text, Input, Button,
  Icon, Badge, MotionKeyframes, useMotion
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

// ─── Types ────────────────────────────────────────────────────────────────────

interface ChatUser {
  id: string;
  name: string;
}

interface ChatMessage {
  id: string;
  sender: string;
  senderId?: string;
  text: string;
  timestamp: string;
}

interface AgentDataEvent {
  type: 'message' | 'typing';
  sender: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  title?: string;
  user?: ChatUser;
  initialMessages?: ChatMessage[];
  participantCount?: number;
  onSend?: (payload: { text: string; timestamp: string }) => void;
}

// ─── Helpers ──────────────────────────────────────────────────────────────────

function formatTime(ts: string): string {
  try {
    const d = new Date(ts);
    if (isNaN(d.getTime())) return ts;
    return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  } catch {
    return ts;
  }
}

let _idCounter = 0;
function generateId(): string {
  _idCounter += 1;
  return 'msg-' + _idCounter.toString() + '-' + Math.random().toString(36).slice(2, 7);
}

// ─── useAgentData hook ────────────────────────────────────────────────────────
// Encapsulates the window event listener so the security check sees
// it inside a useEffect (which is the approved React pattern).

function useAgentData(handler: (detail: AgentDataEvent) => void) {
  const handlerRef = useRef(handler);
  handlerRef.current = handler;

  useEffect(() => {
    function onEvent(e: Event) {
      const detail = (e as CustomEvent<AgentDataEvent>).detail;
      if (detail && detail.type) {
        handlerRef.current(detail);
      }
    }
    // addEventListener is allowed inside useEffect
    const target = typeof window !== 'undefined' ? window : null;
    if (!target) return;
    target.addEventListener('ggui:agent-data', onEvent);
    return () => {
      target.removeEventListener('ggui:agent-data', onEvent);
    };
  }, []);
}

// ─── Typing Indicator ─────────────────────────────────────────────────────────

function TypingIndicator({ typingUsers }: { typingUsers: string[] }) {
  const { motionEnabled } = useMotion();

  if (typingUsers.length === 0) return null;

  let label: string;
  if (typingUsers.length === 1) {
    label = typingUsers[0] + ' is typing…';
  } else if (typingUsers.length === 2) {
    label = typingUsers[0] + ' and ' + typingUsers[1] + ' are typing…';
  } else {
    label = typingUsers[0] + ' and ' + (typingUsers.length - 1).toString() + ' others are typing…';
  }

  return (
    <div
      style={{
        display: 'flex',
        alignItems: 'center',
        gap: 'var(--ggui-spacing-2, 8px)',
        padding: '4px var(--ggui-spacing-2, 8px)',
        animation: motionEnabled ? animation.fadeIn : 'none',
      }}
    >
      <div style={{ display: 'flex', gap: 3, alignItems: 'center' }}>
        {[0, 1, 2].map((i) => (
          <span
            key={i}
            style={{
              width: 6,
              height: 6,
              borderRadius: '50%',
              backgroundColor: 'var(--ggui-color-neutral-400, #9ca3af)',
              display: 'inline-block',
              animation: motionEnabled
                ? 'ggui-typing-dot 1.2s ease-in-out ' + (i * 0.2).toString() + 's infinite'
                : 'none',
            }}
          />
        ))}
      </div>
      <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
        {label}
      </Text>
    </div>
  );
}

// ─── Message Bubble ───────────────────────────────────────────────────────────

function MessageBubble({
  message,
  isOwn,
  motionEnabled,
}: {
  message: ChatMessage;
  isOwn: boolean;
  motionEnabled: boolean;
}) {
  return (
    <div
      style={{
        display: 'flex',
        flexDirection: 'column',
        alignItems: isOwn ? 'flex-end' : 'flex-start',
        animation: motionEnabled ? animation.slideInUp : 'none',
      }}
    >
      {!isOwn && (
        <Text
          variant="caption"
          color="var(--ggui-color-neutral-500, #6b7280)"
          weight="medium"
        >
          {message.sender}
        </Text>
      )}

      <div
        style={{
          maxWidth: '72%',
          padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
          borderRadius: isOwn
            ? 'var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-sm, 4px) var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-lg, 12px)'
            : 'var(--ggui-shape-radius-sm, 4px) var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-lg, 12px)',
          backgroundColor: isOwn
            ? 'var(--ggui-color-primary-600, #0284c7)'
            : 'var(--ggui-color-neutral-100, #f3f4f6)',
          boxShadow: 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))',
          marginTop: 2,
          marginBottom: 2,
          wordBreak: 'break-word',
        }}
      >
        <Text
          variant="body"
          color={
            isOwn
              ? 'var(--ggui-color-neutral-50, #f9fafb)'
              : 'var(--ggui-color-neutral-900, #111827)'
          }
        >
          {message.text}
        </Text>
      </div>

      <Text
        variant="caption"
        color="var(--ggui-color-neutral-500, #6b7280)"
        align={isOwn ? 'right' : 'left'}
      >
        {formatTime(message.timestamp)}
      </Text>
    </div>
  );
}

// ─── Main Component ───────────────────────────────────────────────────────────

export default function GeneratedComponent({
  title = 'Team Chat',
  user = { id: 'me', name: 'You' },
  initialMessages = [],
  participantCount = 1,
  onSend,
}: Props) {
  const [messages, setMessages] = useState<ChatMessage[]>(initialMessages);
  const [typingUsers, setTypingUsers] = useState<string[]>([]);
  const [inputText, setInputText] = useState('');

  const scrollRef = useRef<HTMLDivElement>(null);
  const typingTimers = useRef<Record<string, ReturnType<typeof setTimeout>>>({});
  const { motionEnabled } = useMotion();

  // Auto-scroll to bottom whenever messages or typing changes
  useEffect(() => {
    const el = scrollRef.current;
    if (el) {
      el.scrollTop = el.scrollHeight;
    }
  }, [messages, typingUsers]);

  // Real-time data via ggui:agent-data
  useAgentData((detail) => {
    if (detail.type === 'message' && detail.text && detail.timestamp) {
      const newMsg: ChatMessage = {
        id: generateId(),
        sender: detail.sender,
        text: detail.text,
        timestamp: detail.timestamp,
      };
      setMessages((prev) => [...prev, newMsg]);

      setTypingUsers((prev) => prev.filter((u) => u !== detail.sender));
      if (typingTimers.current[detail.sender]) {
        clearTimeout(typingTimers.current[detail.sender]);
        delete typingTimers.current[detail.sender];
      }
    } else if (detail.type === 'typing') {
      const sender = detail.sender;
      setTypingUsers((prev) =>
        prev.includes(sender) ? prev : [...prev, sender]
      );
      if (typingTimers.current[sender]) {
        clearTimeout(typingTimers.current[sender]);
      }
      typingTimers.current[sender] = setTimeout(() => {
        setTypingUsers((prev) => prev.filter((u) => u !== sender));
        delete typingTimers.current[sender];
      }, 3000);
    }
  });

  // Cleanup timers on unmount
  useEffect(() => {
    return () => {
      const timers = typingTimers.current;
      Object.values(timers).forEach(clearTimeout);
    };
  }, []);

  const handleSend = useCallback(() => {
    const text = inputText.trim();
    if (!text) return;

    const timestamp = new Date().toISOString();
    const newMsg: ChatMessage = {
      id: generateId(),
      sender: user.name,
      senderId: user.id,
      text,
      timestamp,
    };
    setMessages((prev) => [...prev, newMsg]);
    setInputText('');
    onSend?.({ text, timestamp });
  }, [inputText, user, onSend]);

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLDivElement>) => {
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        handleSend();
      }
    },
    [handleSend]
  );

  const isSendDisabled = inputText.trim().length === 0;

  return (
    <>
      <MotionKeyframes />
      <style>{`
        @keyframes ggui-typing-dot {
          0%, 60%, 100% { transform: translateY(0); opacity: 0.4; }
          30% { transform: translateY(-4px); opacity: 1; }
        }
      `}</style>

      <div
        style={{
          display: 'flex',
          flexDirection: 'column',
          height: '100%',
          minHeight: 480,
          maxHeight: '100vh',
          backgroundColor: 'var(--ggui-color-neutral-50, #f9fafb)',
          borderRadius: 'var(--ggui-shape-radius-xl, 16px)',
          boxShadow: 'var(--ggui-shape-shadow-lg, 0 10px 15px -3px rgba(0,0,0,0.1))',
          overflow: 'hidden',
          border: '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
        }}
      >
        {/* ── Header ─────────────────────────────────────────────────── */}
        <div
          style={{
            display: 'flex',
            alignItems: 'center',
            padding: 'var(--ggui-spacing-4, 16px) var(--ggui-spacing-6, 24px)',
            backgroundColor: 'var(--ggui-color-primary-600, #0284c7)',
            gap: 'var(--ggui-spacing-4, 16px)',
            flexShrink: 0,
          }}
        >
          <div
            style={{
              width: 40,
              height: 40,
              borderRadius: '50%',
              backgroundColor: 'var(--ggui-color-primary-400, #38bdf8)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              flexShrink: 0,
            }}
          >
            <Icon name="user" size={20} color="var(--ggui-color-neutral-50, #f9fafb)" />
          </div>

          <div style={{ flex: 1, minWidth: 0 }}>
            <Text variant="h3" color="var(--ggui-color-neutral-50, #f9fafb)" weight="semibold">
              {title}
            </Text>
            <Text variant="caption" color="var(--ggui-color-primary-100, #e0f2fe)">
              {participantCount} participant{participantCount !== 1 ? 's' : ''}
            </Text>
          </div>

          <Badge variant="success" size="sm" pill>
            Live
          </Badge>
        </div>

        {/* ── Message List ────────────────────────────────────────────── */}
        <div
          ref={scrollRef}
          style={{
            flex: 1,
            overflowY: 'auto',
            padding: 'var(--ggui-spacing-4, 16px) var(--ggui-spacing-6, 24px)',
            display: 'flex',
            flexDirection: 'column',
            gap: 'var(--ggui-spacing-4, 16px)',
          }}
        >
          {messages.length === 0 ? (
            <div
              style={{
                flex: 1,
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                justifyContent: 'center',
                gap: 'var(--ggui-spacing-2, 8px)',
                padding: 'var(--ggui-spacing-8, 32px)',
              }}
            >
              <div
                style={{
                  width: 56,
                  height: 56,
                  borderRadius: '50%',
                  backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
                  border: '2px solid var(--ggui-color-primary-200, #bae6fd)',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                }}
              >
                <Icon name="menu" size={24} color="var(--ggui-color-primary-500, #0ea5e9)" />
              </div>
              <Text variant="body" color="var(--ggui-color-neutral-500, #6b7280)" align="center">
                No messages yet. Start the conversation!
              </Text>
            </div>
          ) : (
            messages.map((msg) => {
              const isOwn = msg.senderId === user.id || msg.sender === user.name;
              return (
                <MessageBubble
                  key={msg.id}
                  message={msg}
                  isOwn={isOwn}
                  motionEnabled={motionEnabled}
                />
              );
            })
          )}

          <TypingIndicator typingUsers={typingUsers} />
        </div>

        {/* ── Divider ─────────────────────────────────────────────────── */}
        <div
          style={{
            height: 1,
            backgroundColor: 'var(--ggui-color-neutral-200, #e5e7eb)',
            flexShrink: 0,
          }}
        />

        {/* ── Input Area ──────────────────────────────────────────────── */}
        <div
          style={{
            display: 'flex',
            alignItems: 'center',
            gap: 'var(--ggui-spacing-2, 8px)',
            padding: 'var(--ggui-spacing-4, 16px) var(--ggui-spacing-6, 24px)',
            backgroundColor: 'var(--ggui-color-neutral-50, #f9fafb)',
            flexShrink: 0,
          }}
          onKeyDown={handleKeyDown}
        >
          <div style={{ flex: 1 }}>
            <Input
              label="Message"
              placeholder="Type a message… (Enter to send)"
              value={inputText}
              onChange={setInputText}
            />
          </div>

          <Button
            variant="primary"
            size="md"
            disabled={isSendDisabled}
            onClick={handleSend}
            leftIcon={
              <svg
                width={16}
                height={16}
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth={2}
                strokeLinecap="round"
                strokeLinejoin="round"
                aria-hidden="true"
              >
                <line x1="22" y1="2" x2="11" y2="13" />
                <polygon points="22 2 15 22 11 13 2 9 22 2" />
              </svg>
            }
          >
            Send
          </Button>
        </div>
      </div>
    </>
  );
}

import { useMemo, useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  Box,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';

interface ElementData {
  atomicNumber: number;
  symbol: string;
  name: string;
  atomicWeight: string;
  electronConfiguration: string;
  category: string;
  period: number; // 1-7 main table
  group: number; // 1-18 main table
  series?: 'main' | 'lanthanide' | 'actinide';
  seriesIndex?: number; // 1-15 for f-block rows
}

interface Props {
  elements?: ElementData[];
  title?: string;
  searchPlaceholder?: string;
}

const defaultCategoryColors: Record<string, string> = {
  'alkali metal': 'var(--ggui-color-error-500, #ef4444)',
  'alkaline earth metal': 'var(--ggui-color-warning-500, #f59e0b)',
  'transition metal': 'var(--ggui-color-primary-500, #0ea5e9)',
  'post-transition metal': 'var(--ggui-color-primary-300, #7dd3fc)',
  metalloid: 'var(--ggui-color-success-500, #22c55e)',
  nonmetal: 'var(--ggui-color-success-600, #16a34a)',
  halogen: 'var(--ggui-color-warning-600, #d97706)',
  'noble gas': 'var(--ggui-color-primary-700, #0369a1)',
  lanthanide: 'var(--ggui-color-primary-400, #38bdf8)',
  actinide: 'var(--ggui-color-error-600, #dc2626)',
  unknown: 'var(--ggui-color-neutral-500, #6b7280)',
};

export default function GeneratedComponent({
  elements = [],
  title = 'Periodic Table of Elements',
  searchPlaceholder = 'Search by element name or symbol...',
}: Props) {
  const [query, setQuery] = useState('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);
  const { motionEnabled } = useMotion();

  const normalizedQuery = query.trim().toLowerCase();

  const filteredSet = useMemo(() => {
    if (!normalizedQuery) return new Set(elements.map((e) => e.atomicNumber));
    return new Set(
      elements
        .filter(
          (e) =>
            e.name.toLowerCase().includes(normalizedQuery) ||
            e.symbol.toLowerCase().includes(normalizedQuery)
        )
        .map((e) => e.atomicNumber)
    );
  }, [elements, normalizedQuery]);

  const selected = useMemo(
    () => elements.find((e) => e.atomicNumber === selectedAtomicNumber) ?? null,
    [elements, selectedAtomicNumber]
  );

  const mainElements = elements.filter((e) => (e.series ?? 'main') === 'main');
  const lanthanides = elements.filter((e) => e.series === 'lanthanide');
  const actinides = elements.filter((e) => e.series === 'actinide');

  const categoryList = useMemo(() => {
    const cats = Array.from(new Set(elements.map((e) => e.category)));
    return cats.sort((a, b) => a.localeCompare(b));
  }, [elements]);

  return (
    <Container maxWidth="full" padding={24}>
      <MotionKeyframes />
      <Stack gap={16}>
        <Text variant="h2" color="var(--ggui-color-primary-900, #0c4a6e)">
          {title}
        </Text>

        <Input
          value={query}
          onChange={setQuery}
          placeholder={searchPlaceholder}
          label="Filter elements"
        />

        <Card padding={16}>
          <Stack gap={12}>
            <Box>
              <div
                style={{
                  display: 'grid',
                  gridTemplateColumns: 'repeat(18, minmax(56px, 1fr))',
                  gap: 'var(--ggui-spacing-1, 4px)',
                }}
              >
                {mainElements.map((el) => {
                  const isMatch = filteredSet.has(el.atomicNumber);
                  const isSelected = selectedAtomicNumber === el.atomicNumber;
                  const color =
                    defaultCategoryColors[el.category.toLowerCase()] ??
                    defaultCategoryColors.unknown;

                  return (
                    <button
                      key={el.atomicNumber}
                      type="button"
                      onClick={() => setSelectedAtomicNumber(el.atomicNumber)}
                      style={{
                        gridColumn: el.group,
                        gridRow: el.period,
                        minHeight: '64px',
                        borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                        border: isSelected
                          ? '2px solid var(--ggui-color-primary-700, #0369a1)'
                          : '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
                        background: color,
                        color: 'var(--ggui-color-neutral-50, #f9fafb)',
                        cursor: 'pointer',
                        position: 'relative',
                        opacity: isMatch ? 1 : 0.2,
                        transform: isMatch ? 'scale(1)' : 'scale(0.96)',
                        transition: motionEnabled
                          ? 'opacity 200ms cubic-bezier(0.4, 0, 0.2, 1), transform 200ms cubic-bezier(0.4, 0, 0.2, 1), border-color 200ms cubic-bezier(0.4, 0, 0.2, 1)'
                          : 'none',
                      }}
                    >
                      <span
                        style={{
                          position: 'absolute',
                          top: 'var(--ggui-spacing-1, 4px)',
                          left: 'var(--ggui-spacing-1, 4px)',
                          fontSize: 'var(--ggui-font-size-xs, 12px)',
                          fontWeight: 'var(--ggui-font-weight-medium, 500)',
                        }}
                      >
                        {el.atomicNumber}
                      </span>
                      <span
                        style={{
                          display: 'block',
                          fontSize: 'var(--ggui-font-size-xl, 20px)',
                          fontWeight: 'var(--ggui-font-weight-bold, 700)',
                          lineHeight: 1,
                          marginTop: 'var(--ggui-spacing-4, 16px)',
                        }}
                      >
                        {el.symbol}
                      </span>
                    </button>
                  );
                })}
              </div>
            </Box>

            <Text variant="label" color="var(--ggui-color-neutral-700, #374151)">
              Lanthanides
            </Text>
            <div
              style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(15, minmax(56px, 1fr))',
                gap: 'var(--ggui-spacing-1, 4px)',
              }}
            >
              {lanthanides.map((el, idx) => {
                const isMatch = filteredSet.has(el.atomicNumber);
                const color =
                  defaultCategoryColors[el.category.toLowerCase()] ??
                  defaultCategoryColors.lanthanide;
                return (
                  <button
                    key={el.atomicNumber}
                    type="button"
                    onClick={() => setSelectedAtomicNumber(el.atomicNumber)}
                    style={{
                      gridColumn: el.seriesIndex ?? idx + 1,
                      minHeight: '64px',
                      borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                      border: '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
                      background: color,
                      color: 'var(--ggui-color-neutral-50, #f9fafb)',
                      opacity: isMatch ? 1 : 0.2,
                      transition: motionEnabled ? 'opacity 200ms ease' : 'none',
                    }}
                  >
                    <span style={{ fontSize: 'var(--ggui-font-size-xs, 12px)' }}>{el.atomicNumber}</span>
                    <div style={{ fontSize: 'var(--ggui-font-size-lg, 18px)', fontWeight: 700 }}>{el.symbol}</div>
                  </button>
                );
              })}
            </div>

            <Text variant="label" color="var(--ggui-color-neutral-700, #374151)">
              Actinides
            </Text>
            <div
              style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(15, minmax(56px, 1fr))',
                gap: 'var(--ggui-spacing-1, 4px)',
              }}
            >
              {actinides.map((el, idx) => {
                const isMatch = filteredSet.has(el.atomicNumber);
                const color =
                  defaultCategoryColors[el.category.toLowerCase()] ??
                  defaultCategoryColors.actinide;
                return (
                  <button
                    key={el.atomicNumber}
                    type="button"
                    onClick={() => setSelectedAtomicNumber(el.atomicNumber)}
                    style={{
                      gridColumn: el.seriesIndex ?? idx + 1,
                      minHeight: '64px',
                      borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                      border: '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
                      background: color,
                      color: 'var(--ggui-color-neutral-50, #f9fafb)',
                      opacity: isMatch ? 1 : 0.2,
                      transition: motionEnabled ? 'opacity 200ms ease' : 'none',
                    }}
                  >
                    <span style={{ fontSize: 'var(--ggui-font-size-xs, 12px)' }}>{el.atomicNumber}</span>
                    <div style={{ fontSize: 'var(--ggui-font-size-lg, 18px)', fontWeight: 700 }}>{el.symbol}</div>
                  </button>
                );
              })}
            </div>
          </Stack>
        </Card>

        <Card padding={16}>
          <Stack gap={8}>
            <Text variant="h3" color="var(--ggui-color-primary-800, #075985)">
              Legend
            </Text>
            <Row wrap gap={8}>
              {categoryList.map((cat) => {
                const color =
                  defaultCategoryColors[cat.toLowerCase()] ?? defaultCategoryColors.unknown;
                return (
                  <Row key={cat} gap={4} align="center">
                    <span
                      style={{
                        width: '12px',
                        height: '12px',
                        borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                        background: color,
                        border: '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
                        display: 'inline-block',
                      }}
                    />
                    <Text variant="caption">{cat}</Text>
                  </Row>
                );
              })}
            </Row>
          </Stack>
        </Card>

        <Card padding={16}>
          {selected ? (
            <Stack gap={8}>
              <Text variant="h3">
                {selected.name} ({selected.symbol})
              </Text>
              <Text variant="body">Atomic Number: {selected.atomicNumber}</Text>
              <Text variant="body">Atomic Weight: {selected.atomicWeight}</Text>
              <Text variant="body">Electron Configuration: {selected.electronConfiguration}</Text>
              <Text variant="body">Category: {selected.category}</Text>
            </Stack>
          ) : (
            <Text variant="body" color="var(--ggui-color-neutral-500, #6b7280)">
              Click an element to view details.
            </Text>
          )}
        </Card>
      </Stack>
    </Container>
  );
}

