import React, { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  TextArea,
  Button,
  Divider,
  RadioGroup,
  Checkbox,
  Box,
  Icon,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface FeatureOption {
  value: string;
  label: string;
  description?: string;
}

interface SurveyData {
  name: string;
  email: string;
  satisfaction: string;
  features: string[];
  comments: string;
}

interface Props {
  /** Labels for the 1-5 satisfaction scale */
  satisfactionLabels?: { [key: number]: string };
  /** List of features for the checkbox group */
  featureOptions?: FeatureOption[];
  /** Callback when the survey is submitted */
  onSubmit?: (data: SurveyData) => void;
  /** Title of the survey */
  title?: string;
}

const DEFAULT_SATISFACTION_LABELS: { [key: number]: string } = {
  1: 'Very Dissatisfied',
  2: 'Dissatisfied',
  3: 'Neutral',
  4: 'Satisfied',
  5: 'Very Satisfied',
};

const DEFAULT_FEATURES: FeatureOption[] = [
  { value: 'performance', label: 'Performance', description: 'Speed and responsiveness' },
  { value: 'ui', label: 'User Interface', description: 'Design and layout' },
  { value: 'features', label: 'Feature Set', description: 'Available tools and capabilities' },
  { value: 'support', label: 'Customer Support', description: 'Help and documentation' },
];

/**
 * A comprehensive multi-step survey form with progress tracking and final review.
 */
export default function MultiStepSurvey(props: Props) {
  const {
    satisfactionLabels = DEFAULT_SATISFACTION_LABELS,
    featureOptions = DEFAULT_FEATURES,
    onSubmit,
    title = 'Customer Feedback Survey'
  } = props;

  const { motionEnabled } = useMotion();
  const [step, setStep] = useState(0);
  const [data, setData] = useState<SurveyData>({
    name: '',
    email: '',
    satisfaction: '',
    features: [],
    comments: '',
  });

  const validateEmail = (email: string) => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  };

  const updateField = <K extends keyof SurveyData>(field: K, value: SurveyData[K]) => {
    setData((prev) => {
      const next = { ...prev };
      next[field] = value;
      return next;
    });
  };

  const handleFeatureToggle = (featureValue: string, checked: boolean) => {
    setData((prev) => {
      const features = checked
        ? [...prev.features, featureValue]
        : prev.features.filter((f) => f !== featureValue);
      return { ...prev, features };
    });
  };

  const totalSteps = 5;

  const isStepValid = useMemo(() => {
    if (step === 0) return data.name.trim().length > 0 && validateEmail(data.email);
    if (step === 1) return data.satisfaction !== '';
    if (step === 2) return true;
    if (step === 3) return data.comments.length <= 500;
    return true;
  }, [step, data]);

  const handleNext = () => {
    if (step < totalSteps - 1 && isStepValid) {
      setStep((s) => s + 1);
    }
  };

  const handleBack = () => {
    if (step > 0) {
      setStep((s) => s - 1);
    }
  };

  const handleSubmit = () => {
    if (onSubmit) {
      onSubmit(data);
    }
  };

  const progress = ((step + 1) / totalSteps) * 100;

  return (
    <Container maxWidth="md">
      <MotionKeyframes />
      <Stack gap={32} paddingY={40} role="form" aria-label="Customer Feedback Survey Form">
        <Stack gap={8} align="center">
          <Text variant="h2" align="center" color="var(--ggui-color-primary-900)">
            {title}
          </Text>
          <Text align="center" color="var(--ggui-color-neutral-500)">
            Help us improve our platform with your valuable feedback
          </Text>
        </Stack>

        <Card padding={32} shadow="md">
          <Stack gap={32}>
            {/* Progress Bar */}
            <Stack gap={8}>
              <Row justify="between">
                <Text variant="caption" weight="medium" color="var(--ggui-color-neutral-500)">
                  Step {step + 1} of {totalSteps}
                </Text>
                <Text variant="caption" weight="bold" color="var(--ggui-color-primary-600)">
                  {Math.round(progress)}% Complete
                </Text>
              </Row>
              <Box
                background="var(--ggui-color-neutral-200)"
                borderRadius="var(--ggui-shape-radius-full)"
                style={{ height: 8, overflow: 'hidden' }}
              >
                <div
                  style={{
                    height: '100%',
                    width: progress + '%',
                    background: 'var(--ggui-color-primary-600)',
                    borderRadius: 'var(--ggui-shape-radius-full)',
                    transition: transition.normal,
                  }}
                />
              </Box>
            </Stack>

            {/* Step Content */}
            <Box
              style={{
                minHeight: 300,
                animation: motionEnabled ? animation.fadeIn : 'none',
              }}
              key={step}
            >
              {step === 0 && (
                <Stack gap={20}>
                  <Input
                    label="Full Name"
                    placeholder="Enter your name"
                    value={data.name}
                    onChange={(val) => updateField('name', val)}
                    required
                    error={data.name.trim() === '' && data.name !== '' ? 'Name is required' : undefined}
                  />
                  <Input
                    label="Email Address"
                    type="email"
                    placeholder="you@example.com"
                    value={data.email}
                    onChange={(val) => updateField('email', val)}
                    required
                    error={data.email !== '' && !validateEmail(data.email) ? 'Invalid email format' : undefined}
                  />
                </Stack>
              )}

              {step === 1 && (
                <Stack gap={16}>
                  <Text weight="medium">Overall, how satisfied are you with our service?</Text>
                  <RadioGroup
                    value={data.satisfaction}
                    onChange={(val) => updateField('satisfaction', val)}
                    options={[1, 2, 3, 4, 5].map((num) => ({
                      value: String(num),
                      label: satisfactionLabels[num] || String(num),
                    }))}
                  />
                </Stack>
              )}

              {step === 2 && (
                <Stack gap={16}>
                  <Text weight="medium">Which features are you most interested in?</Text>
                  <Stack gap={12}>
                    {featureOptions.map((opt) => (
                      <Checkbox
                        key={opt.value}
                        label={opt.label}
                        description={opt.description}
                        checked={data.features.includes(opt.value)}
                        onChange={(checked) => handleFeatureToggle(opt.value, checked)}
                      />
                    ))}
                  </Stack>
                </Stack>
              )}

              {step === 3 && (
                <Stack gap={16}>
                  <TextArea
                    label="Any additional comments?"
                    placeholder="Tell us what you think..."
                    value={data.comments}
                    onChange={(val) => updateField('comments', val)}
                    maxLength={500}
                    rows={6}
                  />
                  <Row justify="end">
                    <Text
                      variant="caption"
                      color={data.comments.length > 500 ? 'var(--ggui-color-error-500)' : 'var(--ggui-color-neutral-500)'}
                    >
                      {data.comments.length} / 500 characters
                    </Text>
                  </Row>
                </Stack>
              )}

              {step === 4 && (
                <Stack gap={20}>
                  <Text variant="h3">Review Your Answers</Text>
                  <Card padding={16} border background="var(--ggui-color-neutral-50)">
                    <Stack gap={12}>
                      <Row justify="between">
                        <Text weight="semibold" variant="label">Name</Text>
                        <Text>{data.name}</Text>
                      </Row>
                      <Divider />
                      <Row justify="between">
                        <Text weight="semibold" variant="label">Email</Text>
                        <Text>{data.email}</Text>
                      </Row>
                      <Divider />
                      <Row justify="between">
                        <Text weight="semibold" variant="label">Satisfaction</Text>
                        <Text>{satisfactionLabels[Number(data.satisfaction)] || 'Not selected'}</Text>
                      </Row>
                      <Divider />
                      <Stack gap={4}>
                        <Text weight="semibold" variant="label">Interested Features</Text>
                        {data.features.length > 0 ? (
                          <Row gap={8} wrap>
                            {data.features.map((f) => {
                              const opt = featureOptions.find((o) => o.value === f);
                              return (
                                <Box
                                  key={f}
                                  padding="4px 12px"
                                  borderRadius="var(--ggui-shape-radius-full)"
                                  background="var(--ggui-color-primary-100)"
                                >
                                  <Text variant="caption" color="var(--ggui-color-primary-700)">
                                    {opt ? opt.label : f}
                                  </Text>
                                </Box>
                              );
                            })}
                          </Row>
                        ) : (
                          <Text variant="caption" color="var(--ggui-color-neutral-500)">No features selected</Text>
                        )}
                      </Stack>
                      {data.comments && (
                        <>
                          <Divider />
                          <Stack gap={4}>
                            <Text weight="semibold" variant="label">Comments</Text>
                            <Text variant="bodySmall">{data.comments}</Text>
                          </Stack>
                        </>
                      )}
                    </Stack>
                  </Card>
                </Stack>
              )}
            </Box>

            <Divider />

            <Row justify="between">
              <Button
                variant="outline"
                onClick={handleBack}
                disabled={step === 0}
                leftIcon={<Icon name="chevron-left" size={18} />}
              >
                Back
              </Button>

              {step < totalSteps - 1 ? (
                <Button
                  variant="primary"
                  onClick={handleNext}
                  disabled={!isStepValid}
                  rightIcon={<Icon name="chevron-right" size={18} />}
                >
                  Next Step
                </Button>
              ) : (
                <Button
                  variant="primary"
                  onClick={handleSubmit}
                  leftIcon={<Icon name="check" size={18} />}
                >
                  Submit Survey
                </Button>
              )}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Button,
  Input,
  Select,
  Badge,
  Icon,
  Divider,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

type TaskPriority = 'low' | 'medium' | 'high';
type TaskStatus = 'todo' | 'in-progress' | 'done';

interface Task {
  id: string;
  title: string;
  priority: TaskPriority;
  status: TaskStatus;
  assignee?: string;
  dueDate?: string;
}

interface Props {
  initialTasks?: Task[];
  onTaskUpdate?: (tasks: Task[]) => void;
}

const COLUMNS: { key: TaskStatus; label: string; variant: 'primary' | 'warning' | 'success' }[] = [
  { key: 'todo', label: 'To Do', variant: 'primary' },
  { key: 'in-progress', label: 'In Progress', variant: 'warning' },
  { key: 'done', label: 'Done', variant: 'success' },
];

const VARIANT_COLORS: Record<string, string> = {
  primary: 'var(--ggui-color-primary-500)',
  warning: 'var(--ggui-color-warning-500)',
  success: 'var(--ggui-color-success-500)',
};

const PRIORITY_OPTIONS = [
  { value: 'low', label: 'Low' },
  { value: 'medium', label: 'Medium' },
  { value: 'high', label: 'High' },
];

export default function KanbanBoard({ 
  initialTasks = [], 
  onTaskUpdate 
}: Props) {
  const [tasks, setTasks] = useState<Task[]>(initialTasks);
  const { motionEnabled } = useMotion();

  const stats = useMemo(() => {
    const total = tasks.length;
    const completed = tasks.filter(t => t.status === 'done').length;
    return { total, completed };
  }, [tasks]);

  const updateTasks = (newTasks: Task[]) => {
    setTasks(newTasks);
    onTaskUpdate?.(newTasks);
  };

  const addTask = (column: TaskStatus, title: string, priority: TaskPriority) => {
    const newTask: Task = {
      id: Math.random().toString(36).substring(2, 9),
      title,
      priority,
      status: column,
      assignee: 'User',
      dueDate: new Date().toISOString().split('T')[0],
    };
    updateTasks([...tasks, newTask]);
  };

  const moveTask = (taskId: string, newStatus: TaskStatus) => {
    updateTasks(tasks.map(t => t.id === taskId ? { ...t, status: newStatus } : t));
  };

  const editTask = (taskId: string, updates: Partial<Task>) => {
    updateTasks(tasks.map(t => t.id === taskId ? { ...t, ...updates } : t));
  };

  const removeTask = (taskId: string) => {
    updateTasks(tasks.filter(t => t.id !== taskId));
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <MotionKeyframes />
      <Stack gap={24}>
        {/* Summary Bar */}
        <Card padding="var(--ggui-spacing-4)" border shadow="sm">
          <Row justify="between" align="center" wrap>
            <Stack gap={4}>
              <Text variant="h2" weight="bold">Project Board</Text>
              <Text variant="caption" color="var(--ggui-color-neutral-500)">Manage your team tasks</Text>
            </Stack>
            <Row gap={16} align="center">
              <Badge variant="primary">Total: {stats.total}</Badge>
              <Badge variant="success">Completed: {stats.completed}</Badge>
            </Row>
          </Row>
        </Card>

        {/* Board Columns */}
        <div style={{ 
          display: 'grid', 
          gridTemplateColumns: 'repeat(auto-fit, minmax(320px, 1fr))', 
          gap: 'var(--ggui-spacing-6)',
          alignItems: 'start'
        }}>
          {COLUMNS.map((col) => (
            <KanbanColumn
              key={col.key}
              column={col}
              tasks={tasks.filter(t => t.status === col.key)}
              onAddTask={(title, priority) => addTask(col.key, title, priority)}
              onMoveTask={moveTask}
              onEditTask={editTask}
              onRemoveTask={removeTask}
              motionEnabled={motionEnabled}
            />
          ))}
        </div>
      </Stack>
    </Container>
  );
}

function KanbanColumn({ 
  column, 
  tasks, 
  onAddTask, 
  onMoveTask, 
  onEditTask, 
  onRemoveTask,
  motionEnabled
}: { 
  column: typeof COLUMNS[0];
  tasks: Task[];
  onAddTask: (title: string, priority: TaskPriority) => void;
  onMoveTask: (taskId: string, status: TaskStatus) => void;
  onEditTask: (taskId: string, updates: Partial<Task>) => void;
  onRemoveTask: (taskId: string) => void;
  motionEnabled: boolean;
}) {
  const [isAdding, setIsAdding] = useState(false);

  return (
    <Stack gap={16} style={{ 
      backgroundColor: 'var(--ggui-color-neutral-50)', 
      padding: 'var(--ggui-spacing-4)',
      borderRadius: 'var(--ggui-shape-radius-lg)',
      border: '1px solid var(--ggui-color-neutral-200)',
      minHeight: '600px'
    }}>
      <Row justify="between" align="center">
        <Row gap={8} align="center">
          <div style={{ 
            width: 10, 
            height: 10, 
            borderRadius: 'var(--ggui-shape-radius-full)', 
            backgroundColor: VARIANT_COLORS[column.variant] || 'var(--ggui-color-neutral-300)'
          }} />
          <Text variant="h3" weight="semibold">{column.label}</Text>
        </Row>
        <Badge variant="default">{tasks.length}</Badge>
      </Row>

      <Divider margin={0} />

      <Stack gap={12}>
        {tasks.map((task) => (
          <TaskCard 
            key={task.id} 
            task={task} 
            onMove={(status) => onMoveTask(task.id, status)}
            onEdit={(updates) => onEditTask(task.id, updates)}
            onRemove={() => onRemoveTask(task.id)}
            motionEnabled={motionEnabled}
          />
        ))}

        {isAdding ? (
          <AddTaskForm 
            onSave={(title, priority) => {
              onAddTask(title, priority);
              setIsAdding(false);
            }} 
            onCancel={() => setIsAdding(false)} 
          />
        ) : (
          <Button 
            variant="ghost" 
            fullWidth 
            leftIcon={<Icon name="plus" size={16} />}
            onClick={() => setIsAdding(true)}
          >
            Add Task
          </Button>
        )}
      </Stack>
    </Stack>
  );
}

function TaskCard({ 
  task, 
  onMove, 
  onEdit, 
  onRemove,
  motionEnabled
}: { 
  task: Task; 
  onMove: (status: TaskStatus) => void; 
  onEdit: (updates: Partial<Task>) => void;
  onRemove: () => void;
  motionEnabled: boolean;
}) {
  const [isEditing, setIsEditing] = useState(false);
  const [editValue, setEditValue] = useState(task.title);

  const priorityColor = useMemo(() => {
    switch(task.priority) {
      case 'high': return 'error';
      case 'medium': return 'warning';
      default: return 'success';
    }
  }, [task.priority]);

  const handleSave = () => {
    if (editValue.trim()) {
      onEdit({ title: editValue });
      setIsEditing(false);
    }
  };

  return (
    <Card 
      padding="var(--ggui-spacing-3)" 
      shadow="sm" 
      style={{ 
        animation: motionEnabled ? animation.fadeIn : 'none',
        backgroundColor: 'var(--ggui-color-neutral-50)',
        border: '1px solid var(--ggui-color-neutral-200)',
        cursor: 'default'
      }}
    >
      <Stack gap={12}>
        <Row justify="between" align="start">
          <Badge variant={priorityColor} size="sm">{task.priority.toUpperCase()}</Badge>
          <Row gap={4}>
             <Button variant="ghost" size="xs" onClick={() => setIsEditing(!isEditing)}>
               <Icon name="settings" size={12} />
             </Button>
             <Button variant="ghost" size="xs" onClick={onRemove}>
               <Icon name="x" size={12} />
             </Button>
          </Row>
        </Row>

        {isEditing ? (
          <Stack gap={8}>
            <Input 
              label="Edit Task"
              value={editValue} 
              onChange={setEditValue} 
              placeholder="Task title"
              required
            />
            <Row gap={8} justify="end">
              <Button size="sm" variant="ghost" onClick={() => { setIsEditing(false); setEditValue(task.title); }}>Cancel</Button>
              <Button size="sm" variant="primary" onClick={handleSave}>Save</Button>
            </Row>
          </Stack>
        ) : (
          <Text 
            variant="body" 
            weight="medium" 
            onDoubleClick={() => setIsEditing(true)}
            style={{ cursor: 'text' }}
          >
            {task.title}
          </Text>
        )}

        <Divider margin={0} />

        <Row justify="between" align="center">
          <Row gap={8} align="center">
            <div style={{ 
              width: 24, 
              height: 24, 
              borderRadius: 'var(--ggui-shape-radius-full)', 
              backgroundColor: 'var(--ggui-color-primary-100)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontSize: '10px',
              fontWeight: 'bold',
              color: 'var(--ggui-color-primary-700)'
            }}>
              {task.assignee?.substring(0, 2).toUpperCase() || '??'}
            </div>
            {task.dueDate && (
               <Text variant="caption" color="var(--ggui-color-neutral-500)">
                 {task.dueDate}
               </Text>
            )}
          </Row>

          <Select
            label="Move to"
            value={task.status}
            onChange={(v) => onMove(v as TaskStatus)}
            options={COLUMNS.map(c => ({ value: c.key, label: c.label }))}
            size="sm"
            style={{ width: 'auto', minWidth: '100px' }}
          />
        </Row>
      </Stack>
    </Card>
  );
}

function AddTaskForm({ onSave, onCancel }: { onSave: (title: string, priority: TaskPriority) => void, onCancel: () => void }) {
  const [title, setTitle] = useState('');
  const [priority, setPriority] = useState<TaskPriority>('medium');

  return (
    <Card padding="var(--ggui-spacing-3)" border shadow="md">
      <Stack gap={12}>
        <Input 
          label="Task Title"
          value={title} 
          onChange={setTitle} 
          placeholder="What needs to be done?"
          required
        />
        <Select
          label="Priority"
          value={priority}
          onChange={(v) => setPriority(v as TaskPriority)}
          options={PRIORITY_OPTIONS}
        />
        <Row gap={8} justify="end">
          <Button variant="ghost" size="sm" onClick={onCancel}>Cancel</Button>
          <Button variant="primary" size="sm" onClick={() => title.trim() && onSave(title, priority)}>Create</Button>
        </Row>
      </Stack>
    </Card>
  );
}

