export default function PeriodicTable({
  elements = DEFAULT_ELEMENTS,
  title = 'Periodic Table of Elements'
}: Props) {
  const [search, setSearch] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);
  const { motionEnabled } = useMotion();

  const filteredElements = useMemo(() => {
    if (!search) return elements;
    const s = search.toLowerCase();
    return elements.filter(el =>
      el.name.toLowerCase().includes(s) ||
      el.symbol.toLowerCase().includes(s) ||
      el.number.toString().includes(s)
    );
  }, [elements, search]);

  const categories = useMemo(() => {
    const cats = Array.from(new Set(elements.map(el => el.category)));
    return cats.sort();
  }, [elements]);

  const getElementAt = (period: number, group: number) => {
    return elements.find(el => el.period === period && el.group === group);
  };

  const renderCell = (period: number, group: number) => {
    const el = getElementAt(period, group);
    if (!el) return <Box key={'empty-' + period + '-' + group} />;

    const isMatch = filteredElements.includes(el);
    const isSelected = selectedElement?.number === el.number;
    const categoryColor = CATEGORY_COLORS[el.category] || CATEGORY_COLORS['unknown'];

    return (
      <Card
        key={String(el.number)}
        padding={4}
        shadow={isSelected ? 'md' : 'none'}
        style={{
          gridColumn: group,
          gridRow: period,
          aspectRatio: '1/1',
          cursor: 'pointer',
          border: isSelected
            ? '2px solid var(--ggui-color-primary-600, #0284c7)'
            : '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
          backgroundColor: isMatch ? categoryColor : 'var(--ggui-color-neutral-100, #f3f4f6)',
          opacity: isMatch ? 1 : 0.2,
          transition: transition.normal,
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center',
          position: 'relative',
          overflow: 'hidden',
          animation: motionEnabled && isMatch ? animation.scaleIn : 'none',
        }}
        onClick={() => setSelectedElement(el)}
      >
        <Text
          variant="caption"
          weight="bold"
          style={{
            position: 'absolute',
            top: 'var(--ggui-spacing-1, 4px)',
            left: 'var(--ggui-spacing-1, 4px)',
            fontSize: 'var(--ggui-font-size-xs, 12px)',
            color: isMatch ? 'white' : 'var(--ggui-color-neutral-500, #6b7280)',
            transform: 'scale(0.7)',
            transformOrigin: 'top left'
          }}
        >
          {el.number}
        </Text>
        <Text
          variant="h3"
          weight="bold"
          style={{
            fontSize: 'var(--ggui-font-size-lg, 18px)',
            color: isMatch ? 'white' : 'var(--ggui-color-neutral-500, #6b7280)',
            lineHeight: 1,
          }}
        >
          {el.symbol}
        </Text>
        <Text
          variant="caption"
          style={{
            fontSize: 'var(--ggui-font-size-xs, 12px)',
            transform: 'scale(0.6)',
            color: isMatch ? 'rgba(255,255,255,0.8)' : 'var(--ggui-color-neutral-400, #9ca3af)',
            display: 'block',
            textAlign: 'center',
            maxWidth: '100%',
            overflow: 'hidden',
            textOverflow: 'ellipsis',
            whiteSpace: 'nowrap'
          }}
        >
          {el.name}
        </Text>
      </Card>
    );
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <MotionKeyframes />
      <Stack gap={24}>
        {/* Header Section */}
        <Stack direction="vertical" gap={16}>
          <Text variant="h1" weight="bold">{title}</Text>
          <Row gap={16} align="end" wrap>
            <Box style={{ flex: 1, minWidth: '300px' }}>
              <Input
                label="Search Elements"
                placeholder="Search by name, symbol, or atomic number..."
                value={search}
                onChange={setSearch}
              />
            </Box>
            <Button
              variant="outline"
              onClick={() => { setSearch(''); setSelectedElement(null); }}
            >
              Reset Filters
            </Button>
          </Row>
        </Stack>

        {/* Legend */}
        <Card padding="var(--ggui-spacing-4, 16px)" border>
          <Stack gap={8}>
            <Text variant="label" weight="semibold">Element Categories</Text>
            <Row gap={16} wrap>
              {categories.map(cat => (
                <Row key={cat} gap={8} align="center">
                  <Box
                    style={{
                      width: 16,
                      height: 16,
                      borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                      backgroundColor: CATEGORY_COLORS[cat] || CATEGORY_COLORS['unknown']
                    }}
                  />
                  <Text variant="caption" style={{ textTransform: 'capitalize' }}>{cat}</Text>
                </Row>
              ))}
            </Row>
          </Stack>
        </Card>

        {/* Main View */}
        <Row gap={32} align="start" wrap>
          {/* Table Grid Container */}
          <Box style={{ flex: '3 1 800px', overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-4, 16px)' }}>
            <div
              style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(18, minmax(45px, 1fr))',
                gridTemplateRows: 'repeat(10, minmax(45px, 1fr))',
                gap: 'var(--ggui-spacing-1, 4px)',
                minWidth: '800px',
              }}
            >
              {/* Generate standard grid cells (1-7 periods) */}
              {Array.from({ length: 7 }).map((_, r) =>
                Array.from({ length: 18 }).map((_, c) => renderCell(r + 1, c + 1))
              )}

              {/* Spacer for Lanthanides/Actinides (Row 8) */}
              <Box style={{ gridRow: 8, gridColumn: '1 / span 18', height: 'var(--ggui-spacing-4, 16px)' }} />

              {/* Lanthanides Row (Row 9) - Starting at group 4 */}
              {Array.from({ length: 15 }).map((_, c) => renderCell(9, c + 4))}

              {/* Actinides Row (Row 10) - Starting at group 4 */}
              {Array.from({ length: 15 }).map((_, c) => renderCell(10, c + 4))}
            </div>
          </Box>

          {/* Detail Panel Container */}
