import React, { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Heading,
  Badge,
  Button,
  Icon,
  Tabs,
  Table,
  Divider,
  Box
} from '@ggui-ai/design/primitives';

interface Specification {
  key: string;
  value: string;
}

interface Review {
  author: string;
  rating: number;
  text: string;
  date: string;
}

interface Props {
  productId?: string;
  title?: string;
  price?: number;
  currency?: string;
  rating?: number;
  stock?: number;
  description?: string;
  specifications?: Specification[];
  reviews?: Review[];
  onAddToCart?: (data: { productId: string; quantity: number }) => void;
}

export default function ProductDetailPage({
  productId = 'PROD-001',
  title = 'High-Performance Wireless Headphones',
  price = 299.99,
  currency = '$',
  rating = 4,
  stock = 15,
  description = 'Experience crystal clear sound with our latest wireless headphones. Featuring active noise cancellation and 40-hour battery life.',
  specifications = [
    { key: 'Driver Size', value: '40mm' },
    { key: 'Frequency Response', value: '20Hz - 20kHz' },
    { key: 'Battery Life', value: '40 Hours' },
    { key: 'Bluetooth Version', value: '5.2' },
  ],
  reviews = [
    { author: 'Jane Doe', rating: 5, text: 'Amazing sound quality!', date: '2023-10-01' },
    { author: 'John Smith', rating: 4, text: 'Very comfortable for long sessions.', date: '2023-09-28' },
  ],
  onAddToCart = (data) => console.log('Added to cart:', data),
}: Props) {
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  const handleIncrement = () => {
    if (quantity < stock) setQuantity(prev => prev + 1);
  };

  const handleDecrement = () => {
    if (quantity > 1) setQuantity(prev => prev - 1);
  };

  const handleAddToCart = () => {
    onAddToCart({ productId, quantity });
  };

  const renderStars = (count: number) => {
    const stars = [];
    for (let i = 1; i <= 5; i++) {
      stars.push(
        <span 
          key={i} 
          style={{ 
            color: i <= count ? 'var(--ggui-color-warning-500, #f59e0b)' : 'var(--ggui-color-neutral-300, #d1d5db)',
            fontSize: 'var(--ggui-font-size-lg, 18px)'
          }}
        >
          ★
        </span>
      );
    }
    return <Row gap={2}>{stars}</Row>;
  };

  const getStockBadge = () => {
    if (stock === 0) return <Badge variant="error">Out of Stock</Badge>;
    if (stock <= 5) return <Badge variant="warning">Low Stock ({stock} left)</Badge>;
    return <Badge variant="success">In Stock</Badge>;
  };

  const tabItems = [
    {
      key: 'description',
      label: 'Description',
      content: (
        <Box paddingY={16}>
          <Text variant="body" color="var(--ggui-color-neutral-700, #374151)">
            {description}
          </Text>
        </Box>
      ),
    },
    {
      key: 'specifications',
      label: 'Specifications',
      content: (
        <Box paddingY={16}>
          <Table
            columns={[
              { key: 'key', header: 'Feature', width: '40%' },
              { key: 'value', header: 'Details' },
            ]}
            data={specifications}
            compact
          />
        </Box>
      ),
    },
    {
      key: 'reviews',
      label: 'Reviews',
      content: (
        <Stack gap={16} paddingY={16}>
          {reviews.map((review, index) => (
            <Card key={index} padding={16} shadow="none" border>
              <Stack gap={8}>
                <Row justify="between" align="center">
                  <Text weight="semibold">{review.author}</Text>
                  <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">{review.date}</Text>
                </Row>
                {renderStars(review.rating)}
                <Text variant="body">{review.text}</Text>
              </Stack>
            </Card>
          ))}
          {reviews.length === 0 && <Text align="center" color="var(--ggui-color-neutral-500, #6b7280)">No reviews yet.</Text>}
        </Stack>
      ),
    },
  ];

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap={32}>
        {/* Top Section */}
        <Row wrap gap={32} align="start">
          {/* Image Placeholder */}
          <Box
            style={{
              flex: '1 1 400px',
              height: 400,
              backgroundColor: 'var(--ggui-color-primary-100, #e0f2fe)',
              borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              border: '2px solid var(--ggui-color-primary-200, #bae6fd)',
              minWidth: 300,
            }}
          >
            <Text 
              variant="h3" 
              color="var(--ggui-color-primary-700, #0369a1)"
              weight="bold"
              align="center"
              style={{ padding: 'var(--ggui-spacing-4, 16px)' }}
            >
              {title}
            </Text>
          </Box>

          {/* Product Details Header */}
          <Stack gap={24} style={{ flex: '1 1 300px' }}>
            <Stack gap={8}>
              <Heading level={1}>{title}</Heading>
              <Row align="center" gap={12}>
                {renderStars(rating)}
                <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
                  ({reviews.length} reviews)
                </Text>
              </Row>
              <Text 
                variant="h2" 
                weight="bold" 
                color="var(--ggui-color-primary-600, #0284c7)"
              >
                {currency}{price.toLocaleString()}
              </Text>
              <Box marginY={8}>
                {getStockBadge()}
              </Box>
            </Stack>

            <Divider margin={0} />

            {/* Bottom Actions Section */}
            <Stack gap={16}>
              <Text weight="semibold" variant="label">Quantity</Text>
              <Row gap={12} align="center">
                <Button 
                  variant="outline" 
                  size="sm" 
                  onClick={handleDecrement}
                  disabled={quantity <= 1 || stock === 0}
                >
                  <Icon name="minus" size={16} />
                </Button>
                <Box 
                  style={{ 
                    minWidth: 40, 
                    textAlign: 'center',
                    fontSize: 'var(--ggui-font-size-lg, 18px)',
                    fontWeight: 'var(--ggui-font-weight-medium, 500)'
                  }}
                >
                  {quantity}
                </Box>
                <Button 
                  variant="outline" 
                  size="sm" 
                  onClick={handleIncrement}
                  disabled={quantity >= stock || stock === 0}
                >
                  <Icon name="plus" size={16} />
                </Button>
              </Row>

              <Button 
                variant="primary" 
                size="lg" 
                fullWidth 
                onClick={handleAddToCart}
                disabled={stock === 0}
              >
                {stock === 0 ? 'Out of Stock' : 'Add to Cart'}
              </Button>
            </Stack>
          </Stack>
        </Row>

        {/* Middle Section - Tabs */}
        <Card padding={24}>
          <Tabs 
            items={tabItems} 
            activeKey={activeTab} 
            onChange={setActiveTab} 
            variant="line"
          />
        </Card>
      </Stack>
    </Container>
  );
}

import { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  TextArea,
  Button,
  RadioGroup,
  Checkbox,
  Divider,
} from '@ggui-ai/design/primitives';

interface Props {
  ratingOptions: { value: string; label: string }[];
  featureList: string[];
  onSubmit: (data: any) => void;
}

export default function SurveyForm({
  ratingOptions = [
    { value: '1', label: '1 - Poor' },
    { value: '2', label: '2' },
    { value: '3', label: '3 - Fair' },
    { value: '4', label: '4' },
    { value: '5', label: '5 - Excellent' },
  ],
  featureList = ['Feature A', 'Feature B', 'Feature C'],
  onSubmit,
}: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    rating: '',
    features: [] as string[],
    comments: '',
  });

  const [errors, setErrors] = useState({ name: '', email: '' });

  const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const isStepValid = () => {
    if (step === 1) return formData.name.trim() !== '' && validateEmail(formData.email);
    if (step === 2) return formData.rating !== '';
    return true;
  };

  const updateField = (field: string, value: any) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
    if (field === 'name') setErrors((prev) => ({ ...prev, name: value.trim() ? '' : 'Name is required' }));
    if (field === 'email') setErrors((prev) => ({ ...prev, email: validateEmail(value) ? '' : 'Invalid email format' }));
  };

  const next = () => step < 5 && setStep(s => s + 1);
  const back = () => step > 1 && setStep(s => s - 1);

  return (
    <Container maxWidth="sm">
      <Card padding={24}>
        <Stack gap={16} role="form" aria-label="Survey Form">
          <Text variant="h2">Survey - Step {step} of 5</Text>
          <Divider />
          {step === 1 && (
            <Stack gap={16}>
              <Input label="Name" value={formData.name} onChange={(v) => updateField('name', v)} required error={errors.name} />
              <Input label="Email" type="email" value={formData.email} onChange={(v) => updateField('email', v)} required error={errors.email} />
            </Stack>
          )}
          {step === 2 && (
            <RadioGroup label="Satisfaction Rating" options={ratingOptions} value={formData.rating} onChange={(v) => updateField('rating', v)} />
          )}
          {step === 3 && (
            <Stack gap={8}>
              <Text variant="label">Feature Interests</Text>
              {featureList.map((f) => (
                <Checkbox
                  key={f}
                  label={f}
                  checked={formData.features.includes(f)}
                  onChange={(c) => setFormData(p => ({ ...p, features: c ? [...p.features, f] : p.features.filter(x => x !== f) }))}
                />
              ))}
            </Stack>
          )}
          {step === 4 && (
            <Stack gap={8}>
              <TextArea label="Comments" value={formData.comments} onChange={(v) => updateField('comments', v)} maxLength={500} />
              <Text variant="caption">{formData.comments.length} / 500 characters</Text>
            </Stack>
          )}
          {step === 5 && (
            <Stack gap={8}>
              <Text variant="h3">Review your answers:</Text>
              <Text>Name: {formData.name}</Text>
              <Text>Email: {formData.email}</Text>
              <Text>Rating: {formData.rating}</Text>
              <Text>Features: {formData.features.join(', ')}</Text>
              <Text>Comments: {formData.comments}</Text>
            </Stack>
          )}
          <Divider />
          <Row justify="between">
            <Button variant="secondary" onClick={back} disabled={step === 1}>Back</Button>
            {step < 5 ? (
              <Button onClick={next} disabled={!isStepValid()}>Next</Button>
            ) : (
              <Button variant="primary" onClick={() => onSubmit(formData)}>Submit</Button>
            )}
          </Row>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState } from 'react';
import { Container, Card, Stack, Row, Text, Button, Input, Select, Badge, Box } from '@ggui-ai/design/primitives';

type Priority = 'low' | 'medium' | 'high';
type Status = 'To Do' | 'In Progress' | 'Done';

interface Task {
  id: string;
  title: string;
  priority: Priority;
  assignee: string;
  dueDate: string;
  status: Status;
}

interface Props {
  initialTasks: Task[];
  onTaskUpdate: (task: Task) => void;
}

const PRIORITY_COLORS: Record<Priority, 'success' | 'warning' | 'error'> = {
  low: 'success',
  medium: 'warning',
  high: 'error',
};

export default function KanbanBoard({ initialTasks, onTaskUpdate }: Props) {
  const [tasks, setTasks] = useState<Task[]>(initialTasks);
  const [addingTo, setAddingTo] = useState<Status | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<Priority>('medium');

  const columns: Status[] = ['To Do', 'In Progress', 'Done'];

  const handleAddTask = (status: Status) => {
    if (!newTaskTitle.trim()) return;

    const newTask: Task = {
      id: Math.random().toString(36).substring(2, 11),
      title: newTaskTitle,
      priority: newTaskPriority,
      assignee: 'Unassigned',
      dueDate: new Date().toISOString().split('T')[0],
      status,
    };
    const updatedTasks = [...tasks, newTask];
    setTasks(updatedTasks);
    onTaskUpdate(newTask);
    setAddingTo(null);
    setNewTaskTitle('');
  };

  const moveTask = (taskId: string, newStatus: Status) => {
    const updatedTasks = tasks.map(task =>
      task.id === taskId ? { ...task, status: newStatus } : task
    );
    setTasks(updatedTasks);
    const updatedTask = updatedTasks.find(t => t.id === taskId)!;
    onTaskUpdate(updatedTask);
  };

  const totalTasks = tasks.length;
  const completedTasks = tasks.filter(t => t.status === 'Done').length;

  return (
    <Container maxWidth="full" padding={24}>
      <Stack gap={16}>
        <Card padding={16}>
          <Row justify="between" align="center">
            <Text variant="h2">Project Board</Text>
            <Text>Total Tasks: {totalTasks} | Completed: {completedTasks}</Text>
          </Row>
        </Card>

        <Row gap={16} align="start" wrap={true}>
          {columns.map(status => (
            <Box key={status} style={{ flex: 1, minWidth: '300px' }}>
              <Card padding={16}>
                <Stack gap={16}>
                  <Row justify="between">
                    <Text variant="h3">{status}</Text>
                    <Badge variant="default">{tasks.filter(t => t.status === status).length}</Badge>
                  </Row>

                  <Stack gap={12}>
                    {tasks.filter(t => t.status === status).map(task => (
                      <Card key={task.id} padding={12}>
                        <Stack gap={8}>
                          <Text variant="body" weight="medium">{task.title}</Text>
                          <Row justify="between" align="center">
                            <Badge variant={PRIORITY_COLORS[task.priority]}>{task.priority}</Badge>
                            <Text variant="caption">{task.dueDate}</Text>
                          </Row>
                          <Select
                            label="Change Status"
                            value={task.status}
                            onChange={(val) => moveTask(task.id, val as Status)}
                            options={columns.map(c => ({ value: c, label: c }))}
                          />
                        </Stack>
                      </Card>
                    ))}
                  </Stack>

                  {addingTo === status ? (
                    <Stack gap={8}>
                      <Input label="Task Title" value={newTaskTitle} onChange={setNewTaskTitle} placeholder="Enter task name" />
                      <Select 
                        label="Priority"
                        value={newTaskPriority} 
                        onChange={(v) => setNewTaskPriority(v as Priority)}
                        options={[{value: 'low', label: 'Low'}, {value: 'medium', label: 'Medium'}, {value: 'high', label: 'High'}]}
                      />
                      <Row gap={8}>
                        <Button size="sm" onClick={() => handleAddTask(status)}>Add Task</Button>
                        <Button size="sm" variant="ghost" onClick={() => setAddingTo(null)}>Cancel</Button>
                      </Row>
                    </Stack>
                  ) : (
                    <Button variant="outline" onClick={() => setAddingTo(status)}>+ Add Task</Button>
                  )}
                </Stack>
              </Card>
            </Box>
          ))}
        </Row>
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  Box,
} from '@ggui-ai/design/primitives';

interface Element {
  number: number;
  symbol: string;
  name: string;
  category: string;
  weight: number;
  config: string;
  x: number;
  y: number;
}

interface Props {
  elements: Element[];
}

const CATEGORY_COLORS: Record<string, string> = {
  'Alkali Metals': 'var(--ggui-color-primary-300)',
  'Alkaline Earth Metals': 'var(--ggui-color-primary-400)',
  'Transition Metals': 'var(--ggui-color-primary-500)',
  'Post-transition Metals': 'var(--ggui-color-primary-600)',
  'Metalloids': 'var(--ggui-color-primary-200)',
  'Reactive Nonmetals': 'var(--ggui-color-primary-100)',
  'Noble Gases': 'var(--ggui-color-primary-700)',
  'Lanthanides': 'var(--ggui-color-warning-300)',
  'Actinides': 'var(--ggui-color-warning-500)',
  'Unknown': 'var(--ggui-color-neutral-300)',
};

export default function PeriodicTable({ elements }: Props) {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedElement, setSelectedElement] = useState<Element | null>(null);

  const filteredElements = useMemo(() => {
    const term = searchTerm.toLowerCase();
    return elements.filter(
      (el) =>
        el.name.toLowerCase().includes(term) ||
        el.symbol.toLowerCase().includes(term)
    );
  }, [elements, searchTerm]);

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={24}>
        <Row justify="between" align="center">
          <Text variant="h1">Periodic Table</Text>
          <Input
            label="Search Elements"
            placeholder="Search by name or symbol..."
            value={searchTerm}
            onChange={setSearchTerm}
          />
        </Row>

        <Box style={{ display: 'grid', gridTemplateColumns: 'repeat(18, 1fr)', gap: 'var(--ggui-spacing-1)' }}>
          {elements.map((el) => {
            const isVisible = filteredElements.includes(el);
            return (
              <Card
                key={el.number}
                style={{
                  gridColumn: el.x,
                  gridRow: el.y,
                  opacity: isVisible ? 1 : 0.1,
                  backgroundColor: CATEGORY_COLORS[el.category] || 'var(--ggui-color-neutral-100)',
                  cursor: 'pointer',
                  aspectRatio: '1/1',
                  padding: 'var(--ggui-spacing-1)',
                  transition: 'opacity 0.2s',
                  display: 'flex',
                  flexDirection: 'column',
                  justifyContent: 'center',
                  alignItems: 'center',
                }}
                onClick={() => setSelectedElement(el)}
              >
                <Text variant="caption">{el.number}</Text>
                <Text variant="h3" weight="bold">{el.symbol}</Text>
              </Card>
            );
          })}
        </Box>

        <Card>
          <Text variant="h3">Legend</Text>
          <Row wrap gap={12} style={{ marginTop: 'var(--ggui-spacing-2)' }}>
            {Object.entries(CATEGORY_COLORS).map(([cat, color]) => (
              <Row key={cat} align="center" gap={4}>
                <Box style={{ width: 12, height: 12, borderRadius: '50%', backgroundColor: color }} />
                <Text variant="caption">{cat}</Text>
              </Row>
            ))}
          </Row>
        </Card>
      </Stack>

      {selectedElement && (
        <div
          style={{
            position: 'fixed',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            backgroundColor: 'rgba(0,0,0,0.5)',
            display: 'flex',
            justifyContent: 'center',
            alignItems: 'center',
            zIndex: 1000,
          }}
          onClick={() => setSelectedElement(null)}
        >
          <Card style={{ width: 400, padding: 'var(--ggui-spacing-4)' }} onClick={(e) => e.stopPropagation()}>
            <Stack gap={16}>
              <Text variant="h2">{selectedElement.name} ({selectedElement.symbol})</Text>
              <Text>Atomic Number: {selectedElement.number}</Text>
              <Text>Atomic Weight: {selectedElement.weight}</Text>
              <Text>Category: {selectedElement.category}</Text>
              <Text>Electron Configuration: {selectedElement.config}</Text>
            </Stack>
          </Card>
        </div>
      )}
    </Container>
  );
}

