  onAddToCart: (data: { productId: string; quantity: number }) => void;
}

export default function ProductDetail({
  productId,
  title,
  price,
  currency,
  rating,
  stock,
  description,
  specifications,
  reviews,
  onAddToCart,
}: ProductDetailProps) {
  const [quantity, setQuantity] = useState(1);

  const increment = () => setQuantity((q) => Math.min(q + 1, stock));
  const decrement = () => setQuantity((q) => Math.max(q - 1, 1));

  const ratingStars = Array.from({ length: 5 }).map((_, i) => (
    <Icon key={i} name={i < rating ? 'star' : 'star-outline'} size={16} />
  ));

  const specData = Object.entries(specifications).map(([key, value]) => ({ key, value }));

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={24}>
        <Row gap={24} align="start" style={{ flexWrap: 'wrap' }}>
          <Card style={{ flex: '1 1 300px', height: 300, background: 'var(--ggui-color-primary-100)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <Text variant="h2">{title}</Text>
          </Card>

          <Stack gap={16} style={{ flex: '1 1 300px' }}>
            <Text variant="h1">{title}</Text>
            <Text variant="h3" color="var(--ggui-color-primary-600)">{currency} {price}</Text>
            <Row gap={4}>{ratingStars}</Row>

            <Badge variant={stock > 0 ? (stock < 5 ? 'warning' : 'success') : 'error'}>
              {stock > 0 ? (stock < 5 ? 'Low Stock' : 'In Stock') : 'Out of Stock'}
            </Badge>

            <Spacer />

            <Row gap={8} align="center">
              <Button onClick={decrement} variant="outline" size="sm" disabled={quantity <= 1} aria-label="Decrease quantity">-</Button>
              <Text style={{ minWidth: 40, textAlign: 'center' }}>{quantity}</Text>
              <Button onClick={increment} variant="outline" size="sm" disabled={quantity >= stock} aria-label="Increase quantity">+</Button>
              <Button 
                variant="primary" 
                onClick={() => onAddToCart({ productId, quantity })}
                disabled={stock === 0}
              >
                Add to Cart
              </Button>
            </Row>
          </Stack>
        </Row>

        <Card>
          <Tabs 
            items={[
              {
                key: 'desc',
                label: 'Description',
                content: <Text>{description}</Text>
              },
              {
                key: 'specs',
                label: 'Specifications',
                content: (
                  <Table
                    columns={[
                      { key: 'key', header: 'Feature' },
                      { key: 'value', header: 'Details' }
                    ]}
                    data={specData}
                  />
                )
              },
              {
                key: 'reviews',
                label: 'Reviews',
                content: (
                  <Stack gap={16}>
                    {reviews.map((r, i) => (
                      <Card key={i} border={false} style={{ background: 'var(--ggui-color-neutral-50)' }}>
                        <Stack gap={4}>
                          <Row justify="between">
                            <Text weight="semibold">{r.author}</Text>
                            <Text variant="caption">{r.date}</Text>
                          </Row>
                          <Text variant="caption">Rating: {r.rating}/5</Text>
                          <Text variant="bodySmall">{r.text}</Text>
                        </Stack>
                      </Card>
                    ))}
                  </Stack>
                )
              }
            ]}
          />
        </Card>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Card, Stack, Text, Input, Button, Row } from '@ggui-ai/design/primitives';

interface Message {
  sender: string;
  text: string;
  timestamp: string;
}

interface Props {
  title: string;
  participantCount: number;
  user: { id: string; name: string };
  initialMessages?: Message[];
  onSend: (data: { text: string; timestamp: string }) => void;
  // External listener hook for environment-provided data
  onRegisterAgentListener?: (callback: (data: any) => void) => () => void;
}

export default function ChatInterface({ title, participantCount, user, initialMessages = [], onSend, onRegisterAgentListener }: Props) {
  const [messages, setMessages] = useState<Message[]>(initialMessages);
  const [typingUsers, setTypingUsers] = useState<Set<string>>(new Set());
  const [inputValue, setInputValue] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!onRegisterAgentListener) return;

    const cleanup = onRegisterAgentListener((detail: any) => {
      if (!detail) return;
      if (detail.type === 'message') {
        setMessages((prev) => [...prev, { sender: detail.sender, text: detail.text, timestamp: detail.timestamp }]);
        setTypingUsers((prev) => {
          const next = new Set(prev);
          next.delete(detail.sender);
          return next;
        });
      } else if (detail.type === 'typing') {
        setTypingUsers((prev) => new Set(prev).add(detail.sender));
        setTimeout(() => {
          setTypingUsers((prev) => {
            const next = new Set(prev);
            next.delete(detail.sender);
            return next;
          });
        }, 3000);
      }
    });

    return cleanup;
  }, [onRegisterAgentListener]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, typingUsers]);

  const handleSend = () => {
    const trimmed = inputValue.trim();
    if (!trimmed) return;
    const timestamp = new Date().toISOString();
    onSend({ text: trimmed, timestamp });
    setInputValue('');
  };

  return (
    <Card padding={0} style={{ display: 'flex', flexDirection: 'column', height: '600px', overflow: 'hidden' }}>
      <div style={{ padding: 'var(--ggui-spacing-4)', borderBottom: '1px solid var(--ggui-color-neutral-200)' }}>
        <Text variant="h3">{title}</Text>
        <Text variant="caption" color="var(--ggui-color-neutral-500)">{participantCount} participants</Text>
      </div>

      <div ref={scrollRef} style={{ flex: 1, overflowY: 'auto', padding: 'var(--ggui-spacing-4)' }}>
        <Stack gap={16}>
          {messages.map((msg, i) => {
            const isMe = msg.sender === user.id;
            return (
              <div key={i} style={{ display: 'flex', justifyContent: isMe ? 'flex-end' : 'flex-start' }}>
                <Card padding={12} style={{ maxWidth: '80%', backgroundColor: isMe ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-neutral-100)', border: 'none' }}>
                  <Text variant="caption" weight="bold">{msg.sender}</Text>
                  <Text>{msg.text}</Text>
                  <Text variant="caption" color="var(--ggui-color-neutral-500)">{new Date(msg.timestamp).toLocaleTimeString()}</Text>
                </Card>
              </div>
            );
          })}
          {typingUsers.size > 0 && (
            <Text variant="caption" color="var(--ggui-color-neutral-500)">
              {Array.from(typingUsers).join(', ')} {typingUsers.size > 1 ? 'are' : 'is'} typing...
            </Text>
          )}
        </Stack>
      </div>

      <Row padding={16} style={{ borderTop: '1px solid var(--ggui-color-neutral-200)' }} gap={8}>
        <div style={{ flex: 1 }}>
          <Input 
            label="Message"
            value={inputValue} 
            onChange={setInputValue} 
            placeholder="Type a message..."
          />
        </div>
        <Button 
          variant="primary" 
          disabled={!inputValue.trim()} 
          onClick={handleSend}
        >
          Send
        </Button>
      </Row>
    </Card>
  );
}
